import { EventEmitter } from 'events';
import { SpinController } from '../spin/SpinController';
import pressureConfig from '../config/pressure.config.json';
import { RelicManager } from '../relic/RelicManager';

/**
 * PressureController is the authority on stage difficulty and stage end.
 *
 * Pressure rises each spin by an escalating increment — the longer the run goes,
 * the more each spin costs. Wins actively reduce pressure, so skilled play extends
 * the run. When pressure reaches max the stage ends, regardless of spin count.
 *
 * Increment formula: baseIncrement + (spinsElapsed * escalationRate)
 * Win reduction: winAmount * winReductionFactor
 *
 * Stage end is deferred until after addWin() so a big win on the final spin
 * can pull the player back from the brink before the check resolves.
 */
export class PressureController {
    // Pressure state
    private _pressure: number = 0;
    private _maxPressure: number;
    // Escalation — increment grows each spin so long runs always end eventually
    private _baseIncrement: number;
    private _escalationRate: number;
    private _spinsElapsed: number = 0;
    // Win reduction — larger wins bite off more pressure
    private _winReductionFactor: number;
    // Threshold tracking — each level fires once per stage
    private _thresholds: number[];
    private _thresholdsReached: Set<number> = new Set();
    // Whether the controller is accepting spin events
    private _isActive: boolean = false;
    // Set when pressure hits max mid-spin; addWin() checks this to end the stage
    // after the killing spin's score has been recorded — prevents wins from rescuing
    // the player once the cap is genuinely reached.
    private _stageEndPending: boolean = false;
    // Optional relic modifier source
    private _relicManager: RelicManager | null = null;
    // Events — GameManager subscribes to forward updates and handle stage end
    private _onPressureChanged: EventEmitter = new EventEmitter();
    private _onThresholdReached: EventEmitter = new EventEmitter();
    private _onStageEnded: EventEmitter = new EventEmitter();

    // Getters
    public get pressure(): number { return this._pressure; }
    public get maxPressure(): number { return this._maxPressure; }
    public get ratio(): number { return this._pressure / this._maxPressure; }
    public get onPressureChanged(): EventEmitter { return this._onPressureChanged; }
    public get onThresholdReached(): EventEmitter { return this._onThresholdReached; }
    public get onStageEnded(): EventEmitter { return this._onStageEnded; }
    public set relicManager(rm: RelicManager) { this._relicManager = rm; }

    // Constructor
    constructor(spinController: SpinController) {
        this._maxPressure = pressureConfig.pressureConfig.maxPressure;
        this._baseIncrement = pressureConfig.pressureConfig.baseIncrement;
        this._escalationRate = pressureConfig.pressureConfig.escalationRate;
        this._winReductionFactor = pressureConfig.pressureConfig.winReductionFactor;
        this._thresholds = [...pressureConfig.pressureConfig.thresholds].sort((a, b) => a - b);
        spinController.onSpinComplete.on('complete', () => this._handleSpinComplete());
    }

    /**
     * Begins a new stage. Resets all pressure state and marks the controller active.
     */
    public startStage(): void {
        this._pressure = 0;
        this._spinsElapsed = 0;
        this._thresholdsReached.clear();
        this._isActive = true;
        this._onPressureChanged.emit('changed', this._pressure, this._maxPressure, this.ratio);
    }

    /**
     * Resets pressure without starting a new stage. Call alongside StageController.resetStage().
     */
    public resetStage(): void {
        this._pressure = 0;
        this._spinsElapsed = 0;
        this._thresholdsReached.clear();
        this._stageEndPending = false;
        this._isActive = false;
        this._onPressureChanged.emit('changed', this._pressure, this._maxPressure, this.ratio);
    }

    /**
     * Applies win-based pressure reduction then checks for stage end.
     * GameManager calls this after every spin evaluation, passing 0 on no win.
     * Deferring the stage-end check here means a big win on the killing spin can save the player.
     */
    public addWin(amount: number): void {
        if (!this._isActive) return;
        // Pressure already maxed this spin — end the stage regardless of the win.
        // Score is recorded by GameManager before this call, so it's safely included.
        if (this._stageEndPending) {
            this._stageEndPending = false;
            this._isActive = false;
            this._onStageEnded.emit('ended');
            return;
        }
        if (amount > 0) {
            const reduction = amount * this._winReductionFactor;
            this._pressure = Math.max(0, this._pressure - reduction);
            this._onPressureChanged.emit('changed', this._pressure, this._maxPressure, this.ratio);
        }
        if (this._pressure >= this._maxPressure) {
            this._isActive = false;
            this._onStageEnded.emit('ended');
        }
    }

    /**
     * Applies the escalating pressure increment for one spin and checks thresholds.
     * Stage end is NOT checked here — addWin() handles that after win reduction applies.
     */
    private _handleSpinComplete(): void {
        if (!this._isActive) return;
        this._spinsElapsed++;
        const pressureMultiplier = this._relicManager?.getPressureMultiplier() ?? 1;
        const increment = (this._baseIncrement + (this._spinsElapsed * this._escalationRate)) * pressureMultiplier;
        this._pressure = Math.min(this._pressure + increment, this._maxPressure);
        this._onPressureChanged.emit('changed', this._pressure, this._maxPressure, this.ratio);
        this._checkThresholds();
        if (this._pressure >= this._maxPressure) {
            this._stageEndPending = true;
        }
    }

    /**
     * Fires each threshold event once per stage when its level is newly crossed.
     */
    private _checkThresholds(): void {
        const currentPercent = this.ratio * 100;
        const shift = this._relicManager?.getThresholdShift() ?? 0;
        for (const threshold of this._thresholds) {
            if (!this._thresholdsReached.has(threshold) && currentPercent >= threshold + shift) {
                this._thresholdsReached.add(threshold);
                this._onThresholdReached.emit('reached', threshold);
            }
        }
    }
}
