import * as PIXI from 'pixi.js';
import { SymbolView } from './view/SymbolView';
import baseReelConfig from '../config/baseReel.config.json';
import skillWindowConfig from '../config/skillWindow.config.json';
import nudgeConfig from '../config/nudge.config.json';
import { ReelStrip } from './ReelStrip';

/**
 * ReelState defines the possible states of a reel during the spinning process.
 */
export enum ReelState { IDLE, SPINNING, STOPPING }

/**
 * Reel represents a single reel in the slot machine game. 
 * It manages the symbols displayed on the reel, handles the spinning logic, and determines when to stop based on the target symbol index and timing.
 */
export class Reel {
    // Visual
    private _container: PIXI.Container = new PIXI.Container();
    private _reelStrip: ReelStrip;
    private _symbolViews: SymbolView[] = [];
    // Per-view strip index tracking — parallel to _symbolViews.
    // Updated whenever a view is recycled so _snapToGrid can identify exactly which strip index is at TOP.
    private _viewStripIndices: number[] = [];
    // Data
    private _symbolHeight: number;
    private _spinSpeed: number;
    private _currentOffset: number = 0;
    private _currentNotchIndex: number;
    private _notchCount: number;
    private _visibleCount: number;
    private _stripIndex: number = 0;
    private _plannedStops: number[] | null = null;
    private _plannedIndex: number = 0;
    // State
    private _state: ReelState = ReelState.IDLE;
    // Nudge slide animation
    private _nudgeSlideRemaining: number = 0;
    private _nudgeSlideSpeed: number = 0;
    private _nudgeSlideDir: number = 0;
    // Skill window highlight — drawn over the visible reel area when a qualifying symbol is approaching
    private _highlightBorder: PIXI.Graphics = new PIXI.Graphics();
    private _reelWidth: number;
    private _reelVisibleHeight: number;

    // Getters
    public get container(): PIXI.Container {
        return this._container;
    }

    public get notchCount(): number {
        return this._notchCount;
    }

    public get reelState(): ReelState {
        return this._state;
    }

    public get currentIndex(): number {
        return this._stripIndex;
    }

    // Constructor
    public constructor(reelStrip: ReelStrip, width: number, height: number) {
        this._reelStrip = reelStrip;
        this._symbolHeight = baseReelConfig.baseReelConfig.symbolHeight;
        this._spinSpeed = baseReelConfig.baseReelConfig.spinSpeed;
        this._notchCount = reelStrip.length;
        this._currentNotchIndex = 0;
        this._stripIndex = (this._notchCount - 1);
        this._reelWidth = width;
        this._reelVisibleHeight = height;
        // Initialize symbol views based on the reel strip and layout
        const visibleCount = Math.floor(height / this._symbolHeight);
        this._visibleCount = visibleCount;
        const totalSymbols = visibleCount + 2;
        for (let i = 0; i < totalSymbols; i++) {
            const index = (this._currentNotchIndex - 1 + i + this._notchCount * 10) % this._notchCount;
            const model = this._reelStrip.getSymbol(index);
            const view = new SymbolView(model, width, this._symbolHeight);
            view.sprite.y = (i - 1) * this._symbolHeight;
            this._container.addChild(view.sprite);
            this._symbolViews.push(view);
            this._viewStripIndices.push(index);
        }
        // Highlight border sits above all symbol views, hidden until a qualifying symbol approaches
        this._container.addChild(this._highlightBorder);
    }

    /** 
     * Update method to be called on each game tick, which updates the position of the symbols based on the current state of the reel (spinning or stopping).
     */
    public update(delta: number): void {
        if (this._nudgeSlideRemaining > 0) {
            const move = Math.min(this._nudgeSlideSpeed * delta, this._nudgeSlideRemaining);
            this._symbolViews.forEach(view => { view.sprite.y += this._nudgeSlideDir * move; });
            this._nudgeSlideRemaining -= move;
            if (this._nudgeSlideRemaining <= 0) {
                this._finishNudgeSlide();
            }
            return;
        }
        if (this._state === ReelState.IDLE) { return; }
        else if (this._state === ReelState.SPINNING) { this._moveSymbols(delta); }
        else if (this._state === ReelState.STOPPING) {
            this._moveSymbols(delta);
            if (this._plannedStops && this._plannedIndex >= this._plannedStops.length) {
                this._snapToGrid();
                this._state = ReelState.IDLE;
            }
        }
    }

    /** 
     * Starts the spinning of the reel.
     */
    public spin(): void {
        if (this._state === ReelState.SPINNING) { return; }
        this._state = ReelState.SPINNING;
        this._plannedStops = null;
        this._plannedIndex = 0;
    }

    /**
     * Stops the spinning of the reel
     */
    public stop(): void {
        if (this._state !== ReelState.SPINNING) {
            return;
        }
        this._state = ReelState.STOPPING;
    }

    /**
    * Sets a predetermined sequence of notch indices for the reel to follow during stopping, ensuring deterministic landing on the correct symbol.
    */
    public setPlannedStops(sequence: number[]): void {
        this._plannedStops = sequence;
        this._plannedIndex = 0;
    }

    /**
     * Calculates the distance to the next notch based on the current offset of the symbols and the symbol height. 
     * This is used to determine when to stop the reel during the stopping phase to ensure it lands on the correct symbol.
     */
    private _distanceToNextNotch(): number {
        const next = Math.ceil(this._currentOffset / this._symbolHeight) * this._symbolHeight;
        return next - this._currentOffset;
    }

    /**
     * Handles the looping of symbols when they move beyond the visible area, ensuring a continuous spinning effect.
     */
    private _handleLooping(): void {
        const bottomThreshold = this._symbolHeight * (this._symbolViews.length - 1);
        for (let i = 0; i < this._symbolViews.length; i++) {
            const view = this._symbolViews[i];
            if (view.sprite.y >= bottomThreshold) {
                view.sprite.y -= this._symbolViews.length * this._symbolHeight;

                if (this._plannedStops && this._plannedIndex < this._plannedStops.length) {
                    this._stripIndex = this._plannedStops[this._plannedIndex];
                    this._plannedIndex++;
                } else {
                    this._stripIndex = (this._stripIndex - 1 + this._notchCount) % this._notchCount;
                }

                // Keep per-view strip index in sync so _snapToGrid knows what each view holds
                this._viewStripIndices[i] = this._stripIndex;
                view.setModel(this._reelStrip.getSymbol(this._stripIndex));
            }
        }
    }

    /**
     * Moves the symbols based on the current spin speed and the elapsed time (delta).
     */
    private _moveSymbols(delta: number): void {
        let move = this._spinSpeed * delta;
        this._symbolViews.forEach(symbolView => { symbolView.sprite.y += move; });
        this._currentOffset += move;
        this._handleLooping();
    }

    /**
     * Snaps the symbols to the grid based on the symbol height, ensuring that the reel lands perfectly on a symbol when stopping.
     */
    private _snapToGrid(): void {
        // Find the view physically closest to y=0 (the TOP slot) and snap it there.
        // Using actual positions rather than _currentOffset % symbolHeight, because recycling
        // causes 875px jumps in view positions that are not reflected in _currentOffset.
        let closestIdx = 0;
        let minDist = Infinity;
        for (let i = 0; i < this._symbolViews.length; i++) {
            const dist = Math.abs(this._symbolViews[i].sprite.y);
            if (dist < minDist) {
                minDist = dist;
                closestIdx = i;
            }
        }
        const topView = this._symbolViews[closestIdx];
        if (topView.sprite.y === 0) return;
        const correction = -topView.sprite.y;
        this._symbolViews.forEach(view => { view.sprite.y += correction; });
        this._currentOffset += correction;
        // Set _stripIndex so WinManager's formula (stopIndex + rowOffset + 1) resolves correctly.
        // The view now at y=0 holds _viewStripIndices[closestIdx], so _stripIndex must be one less.
        const topStripIndex = this._viewStripIndices[closestIdx];
        this._stripIndex = (topStripIndex - 1 + this._notchCount) % this._notchCount;
    }

    /**
     * Shifts all symbol views by one row in the given direction and updates _stripIndex.
     * UP brings the buffer-above symbol into the top row.
     * DOWN brings the buffer-below symbol into the bottom row.
     * Only valid when the reel is IDLE (already stopped).
     */
    public nudge(direction: 'up' | 'down'): void {
        if (this._state !== ReelState.IDLE || this._nudgeSlideRemaining > 0) return;
        // UP: content moves up (-y), new symbol slides in from below, strip index increases
        // DOWN: content moves down (+y), new symbol slides in from above, strip index decreases
        if (direction === 'up') {
            this._nudgeSlideDir = -1;
            this._stripIndex = (this._stripIndex + 1) % this._notchCount;
        } else {
            this._nudgeSlideDir = 1;
            this._stripIndex = (this._stripIndex - 1 + this._notchCount) % this._notchCount;
        }
        const duration = nudgeConfig.nudgeConfig.nudgeAnimDuration;
        this._nudgeSlideSpeed = this._symbolHeight / duration;
        this._nudgeSlideRemaining = this._symbolHeight;
    }

    /**
     * Called when the nudge slide animation completes.
     * Recycles the buffer view that escaped off-screen to the opposite side,
     * assigns it the next sequential strip symbol, and snaps all views to the grid.
     */
    private _finishNudgeSlide(): void {
        const isUp = this._nudgeSlideDir === -1;
        if (isUp) {
            // Content moved up: the old buffer-above escaped off the top (most negative y).
            // Reposition it to the buffer-below slot and assign the next strip symbol.
            const escapedIdx = this._symbolViews.reduce(
                (minI, v, i) => v.sprite.y < this._symbolViews[minI].sprite.y ? i : minI, 0
            );
            this._symbolViews[escapedIdx].sprite.y = this._visibleCount * this._symbolHeight;
            const newSymbolIdx = (this._stripIndex + this._visibleCount + 1) % this._notchCount;
            this._symbolViews[escapedIdx].setModel(this._reelStrip.getSymbol(newSymbolIdx));
            this._viewStripIndices[escapedIdx] = newSymbolIdx;
        } else {
            // Content moved down: the old buffer-below escaped off the bottom (most positive y).
            // Reposition it to the buffer-above slot and assign the new leading strip symbol.
            const escapedIdx = this._symbolViews.reduce(
                (maxI, v, i) => v.sprite.y > this._symbolViews[maxI].sprite.y ? i : maxI, 0
            );
            this._symbolViews[escapedIdx].sprite.y = -this._symbolHeight;
            const newSymbolIdx = this._stripIndex;
            this._symbolViews[escapedIdx].setModel(this._reelStrip.getSymbol(newSymbolIdx));
            this._viewStripIndices[escapedIdx] = newSymbolIdx;
        }
        // Remove any float drift accumulated during the animation
        this._symbolViews.forEach(view => {
            view.sprite.y = Math.round(view.sprite.y / this._symbolHeight) * this._symbolHeight;
        });
    }

    /**
     * Shows or hides the skill window highlight border over the visible reel area.
     * Called by SkillWindowController when a qualifying symbol is in the approach position.
     */
    public showHighlight(active: boolean): void {
        this._highlightBorder.clear();
        if (!active) return;
        const cfg = skillWindowConfig.skillWindowConfig;
        this._highlightBorder
            .rect(0, 0, this._reelWidth, this._reelVisibleHeight)
            .stroke({ color: cfg.highlightColor, width: cfg.highlightWidth, alpha: cfg.highlightAlpha });
    }

    /**
     * Immediately snaps the reel to the nearest grid position and transitions to IDLE.
     * Used for manual stop — locks in exactly the symbols visible at the moment the player acts.
     * Because free-spinning maintains sequential strip indices across all views, the snap
     * position is always evaluation-consistent without any additional recycling steps.
     */
    public snapStop(): void {
        if (this._state !== ReelState.SPINNING) { return; }
        this._snapToGrid();
        this._state = ReelState.IDLE;
    }

    /**
     * Returns the total number of symbol views (visible rows + above/below buffer).
     * Used by SpinController to determine how many planned stop steps are required
     * so that every view gets updated with a correct sequential strip index.
     */
    public get viewCount(): number {
        return this._symbolViews.length;
    }
}