import * as PIXI from 'pixi.js';

/**
 * Renderer is responsible for initializing the PIXI application, managing the main stage, and loading assets.
 */
export class Renderer {
    private _application: PIXI.Application;

    //Getters
    public get app(): PIXI.Application {
        return this._application;
    }

    // Contructor
    public constructor() {
        // Initialize PIXI application and add canvas to document body
        this._application = new PIXI.Application();
        void this._application
            .init({
                backgroundColor: 0x000000,
                width: window.innerWidth,
                height: window.innerHeight,
            })
            .then(() => {
                document.body.appendChild(this._application.canvas);
            });
        // Listen for window resize events to make the renderer responsive
        window.addEventListener('resize', () => {
            this._application.renderer?.resize(window.innerWidth, window.innerHeight);
        });
    }

    public get stage(): PIXI.Container {
        return this._application.stage;
    }

    public get ticker(): PIXI.Ticker {
        return this._application.ticker;
    }

    /**
     * Loads required assets for the game based on the provided configuration.
     */
    public async loadAssets(config: any): Promise<void> {
        let assets: string[] = [];
        if (config.symbols) {
            assets = config.symbols.map((s: any) => s.texture);
        } else {
            assets = Object.values(config);
        }
        await PIXI.Assets.load(assets);
    }
}

export default Renderer;
