import { TextBox } from './TextBox';
import * as PIXI from 'pixi.js';

/**
 * A WinBox class that extends TextBox. 
 * It is designed to display a winning message with a specific style and can be resized as needed.
 */
export class WinBox extends TextBox {
    private _height = 60;

    // Constructor
    constructor(width: number) {
        super('', width, 60);

        // Customize style
        this._text.style = new PIXI.TextStyle({
            fill: 0xffffff,
            fontWeight: 'bold',
            fontSize: 32
        });

        this._redraw(width);
    }

    // Public method to resize the win box based on the new width
    public resize(width: number): void {
        this._redraw(width);
    }

    // Override the show method to display the win amount in the win box
    public show(amount: number): void {
        if (amount <= 0) {
            this.text = '';
            return;
        }
        this.text = `WIN ${amount}`;
    }

    public clear(): void {
        this.text = '';
    }

    // Redraw the background and reposition the text based on the new width
    private _redraw(width: number): void {
        this._background.clear();
        this._background
            .rect(-width / 2, 0, width, this._height)
            .fill({ color: 0x000000, alpha: 1 });

        this.centerText();
        this._text.position.set(0, this._height / 2);
    }
}