import * as PIXI from 'pixi.js';
import { EventEmitter } from 'events';
import { Scene } from './Scene';
import { RelicData } from '../relic/RelicManager';

export const RELIC_SELECTED_EVENT = 'relicSelected';

const CARD_W = 180;
const CARD_H = 290;
const CARD_GAP = 24;

/**
 * RelicSelectScene presents up to 3 temple relic options as stone-tablet cards
 * after a stage ends. The player clicks one to carry it into the next stage.
 * GameManager passes options from RelicManager and listens to onRelicSelected.
 */
export class RelicSelectScene extends Scene {
    private _onRelicSelected: EventEmitter = new EventEmitter();
    private _cards: PIXI.Container[] = [];

    public get onRelicSelected(): EventEmitter { return this._onRelicSelected; }

    public async init(): Promise<void> {
        this._buildBackground();
        this._updateAnchor();
    }

    /**
     * Builds and shows the relic option cards. Called by GameManager with fresh options each time.
     */
    public show(options: RelicData[]): void {
        this._clearCards();
        const totalWidth = options.length * CARD_W + (options.length - 1) * CARD_GAP;
        const startX = -totalWidth / 2;
        options.forEach((relic, i) => {
            const card = this._buildCard(relic);
            card.position.set(startX + i * (CARD_W + CARD_GAP), -CARD_H / 2);
            this._container.addChild(card);
            this._cards.push(card);
        });
        this._updateAnchor();
        this.visible = true;
    }

    public hide(): void {
        this.visible = false;
        this._clearCards();
    }

    private _buildBackground(): void {
        const totalCardsWidth = 3 * CARD_W + 2 * CARD_GAP;
        const bgW = totalCardsWidth + 80;
        const bgH = CARD_H + 120;
        const bg = new PIXI.Graphics()
            .rect(-bgW / 2, -bgH / 2, bgW, bgH)
            .fill({ color: 0x0d0b09, alpha: 0.95 })
            .rect(-bgW / 2, -bgH / 2, bgW, bgH)
            .stroke({ color: 0x4a3c2a, width: 2 });
        this._container.addChild(bg);

        const title = new PIXI.Text({
            text: 'A Temple Relic Awaits',
            style: new PIXI.TextStyle({ fill: 0xd4c5b0, fontSize: 24, fontWeight: 'bold', align: 'center' })
        });
        title.anchor.set(0.5);
        title.position.set(0, -bgH / 2 + 36);
        this._container.addChild(title);
    }

    private _buildCard(relic: RelicData): PIXI.Container {
        const card = new PIXI.Container();

        const bg = new PIXI.Graphics()
            .rect(0, 0, CARD_W, CARD_H)
            .fill(0x1a1612);
        const border = new PIXI.Graphics()
            .rect(0, 0, CARD_W, CARD_H)
            .stroke({ color: 0x4a3c2a, width: 2 });

        const swatch = new PIXI.Graphics()
            .circle(CARD_W / 2, 52, 22)
            .fill(relic.color);

        const nameText = new PIXI.Text({
            text: relic.name,
            style: new PIXI.TextStyle({
                fill: 0xd4c5b0, fontSize: 16, fontWeight: 'bold',
                wordWrap: true, wordWrapWidth: CARD_W - 20, align: 'center'
            })
        });
        nameText.anchor.set(0.5, 0);
        nameText.position.set(CARD_W / 2, 88);

        const descText = new PIXI.Text({
            text: relic.description,
            style: new PIXI.TextStyle({
                fill: 0x8a7d6e, fontSize: 13,
                wordWrap: true, wordWrapWidth: CARD_W - 24, align: 'center'
            })
        });
        descText.anchor.set(0.5, 0);
        descText.position.set(CARD_W / 2, 140);

        card.addChild(bg, border, swatch, nameText, descText);
        card.eventMode = 'static';
        card.cursor = 'pointer';

        card.on('pointerover', () => {
            border.clear().rect(0, 0, CARD_W, CARD_H).stroke({ color: 0xd4af37, width: 2 });
        });
        card.on('pointerout', () => {
            border.clear().rect(0, 0, CARD_W, CARD_H).stroke({ color: 0x4a3c2a, width: 2 });
        });
        card.on('pointerdown', () => {
            this._onRelicSelected.emit(RELIC_SELECTED_EVENT, relic);
        });

        return card;
    }

    private _clearCards(): void {
        this._cards.forEach(c => this._container.removeChild(c));
        this._cards = [];
    }
}
