import { Button } from './Button';
import * as PIXI from 'pixi.js';

/**
 * SpinButton is a specialized button component that extends the base Button class to create a circular spin button for the slot machine game.
 */
export class SpinButton extends Button {
    /**
     * Constructor
     * It initializes the SpinButton with a circular shape and applies a custom drawing function if provided. 
     * If no custom drawing function is provided, it defaults to drawing a red circle with the specified radius.
     */
    constructor(radius: number, onClick: () => void, draw?: (graphics: PIXI.Graphics) => void) {
        super(onClick);
        if (draw) {
            draw(this.view);
        } else {
            this.view.circle(0, 0, radius).fill(0xff0000);
        }
        this.view.pivot.set(0, 0);
    }
}