import * as PIXI from 'pixi.js';

// Dark greenish-black tint — stone and moss corruption
const CORRUPTION_COLOR = 0x081a08;
// Width of the edge bands that creep in from each border
const EDGE_BAND = 30;

/**
 * CorruptionOverlay is a transparent PIXI container that renders a darkening vignette
 * over the slot area as pressure builds. Intensity is driven externally via setIntensity().
 *
 * At low pressure the overlay is invisible. As ratio rises, a full-area dark tint grows
 * alongside stronger edge bands that frame the slot area from each side. Together they
 * create a feeling of the space closing in without obscuring gameplay.
 *
 * This class owns all visual logic. Callers only need to pass a 0..1 ratio.
 * Extend or replace this class to add shaders, particles, or per-threshold animations.
 */
export class CorruptionOverlay extends PIXI.Container {
    private _graphics: PIXI.Graphics = new PIXI.Graphics();
    private _slotWidth: number;
    private _slotHeight: number;

    constructor(slotWidth: number, slotHeight: number) {
        super();
        this._slotWidth = slotWidth;
        this._slotHeight = slotHeight;
        this.addChild(this._graphics);
        // Passthrough — this container must never swallow pointer events from the reels
        this.eventMode = 'none';
        this._draw(0);
    }

    /**
     * Updates the overlay to reflect the current pressure ratio (0..1).
     * Called by BaseGameScene whenever PressureController fires a change event.
     */
    public setIntensity(ratio: number): void {
        this._draw(ratio);
    }

    private _draw(ratio: number): void {
        const w = this._slotWidth;
        const h = this._slotHeight;
        this._graphics.clear();
        if (ratio <= 0) return;

        // Full-area base tint — the entire slot darkens gradually
        this._graphics.rect(0, 0, w, h).fill({ color: CORRUPTION_COLOR, alpha: ratio * 0.35 });

        // Outer edge bands — stronger darkening along each border
        const edgeAlpha = ratio * 0.6;
        this._graphics.rect(0, 0, w, EDGE_BAND).fill({ color: CORRUPTION_COLOR, alpha: edgeAlpha });
        this._graphics.rect(0, h - EDGE_BAND, w, EDGE_BAND).fill({ color: CORRUPTION_COLOR, alpha: edgeAlpha });
        this._graphics.rect(0, 0, EDGE_BAND, h).fill({ color: CORRUPTION_COLOR, alpha: edgeAlpha });
        this._graphics.rect(w - EDGE_BAND, 0, EDGE_BAND, h).fill({ color: CORRUPTION_COLOR, alpha: edgeAlpha });

        // Inner edge rings — a second inset band for vignette depth
        const innerAlpha = ratio * 0.25;
        const ib = EDGE_BAND * 2;
        this._graphics.rect(EDGE_BAND, EDGE_BAND, w - EDGE_BAND * 2, EDGE_BAND).fill({ color: CORRUPTION_COLOR, alpha: innerAlpha });
        this._graphics.rect(EDGE_BAND, h - ib, w - EDGE_BAND * 2, EDGE_BAND).fill({ color: CORRUPTION_COLOR, alpha: innerAlpha });
        this._graphics.rect(EDGE_BAND, EDGE_BAND, EDGE_BAND, h - EDGE_BAND * 2).fill({ color: CORRUPTION_COLOR, alpha: innerAlpha });
        this._graphics.rect(w - ib, EDGE_BAND, EDGE_BAND, h - EDGE_BAND * 2).fill({ color: CORRUPTION_COLOR, alpha: innerAlpha });
    }
}
