import EventEmitter from 'events';
import { Assets } from 'pixi.js';

/**
 * SpinData represents predetermined spin results, where each key is a unique identifier for a spin scenario and the value is an array of reel indices
 */
export interface SpinData {
    [key: string]: number[];
}

/**
 * ReelsetData represents the configuration of a reel set, including its unique identifier and the symbols on each reel. 
 * Each reel is represented as an array of symbol IDs.
 */
export interface ReelsetData {
    id: string;
    reels: number[][];
}

/**
 * DataManager is responsible for loading and managing game data, including reel configurations and predetermined spin results. 
 * It provides methods to access this data and emits events when the data is loaded, allowing other parts of the application to react accordingly. 
 */
export class DataManager {
    // Data
    private _reelsets: ReelsetData[] = [];
    private _spinData: Record<string, SpinData> = {};
    // Events
    private _reelsetDataLoaded: EventEmitter = new EventEmitter();
    private _testDataLoaded: EventEmitter = new EventEmitter();

    // Getters
    public get testDataLoaded(): EventEmitter {
        return this._testDataLoaded;
    }

    public get reelsetDataLoaded(): EventEmitter {
        return this._reelsetDataLoaded;
    }

    public get spinData(): Record<string, SpinData> {
        return this._spinData;
    }

    public get reelsets(): ReelsetData[] {
        return this._reelsets;
    }

    // Constructor
    constructor() {
        this._loadSpinData();
        this._loadReelsetData();
    }

    /**
     * Loads test data files using manifest and stores test scenarios. 
     * Emits an event when loading is complete.
     */
    private async _loadSpinData(): Promise<void> {
        // Load manifest
        const manifest = await Assets.load('resources/testData/manifest.json') as {
            files: string[];
        };
        // Load each test data file
        for (const name of manifest.files) {
            const data = await Assets.load(`resources/testData/${name}.json`);
            this._spinData[name] = data as SpinData;
        }
        // Emit signal that test data is loaded
        this._testDataLoaded.emit('testDataLoaded');
    }

    /**
     * Loads reelset data from a JSON file, processes it, and stores it in the DataManager. 
     * Emits an event when loading is complete.
     */
    private async _loadReelsetData(): Promise<void> {
        // Load reelset data from JSON file
        const reelsetData = await Assets.load('resources/reelsets/reelset.json') as {
            reelsets: { id: string; reels: number[][] }[];
        };
        // Process reelsetData into id and reels format and store in DataManager
        this._reelsets = reelsetData.reelsets.map(reelset => ({
            id: reelset.id,
            reels: reelset.reels
        }));
        // Emit signal that reelset data is loaded
        this._reelsetDataLoaded.emit('reelsetsLoaded');
    }

}