import * as PIXI from 'pixi.js';
import { SymbolModel } from '../model/SymbolModel';

/**
 * SymbolView represents the visual representation of a symbol in the slot machine game. 
 * It encapsulates a PIXI.Sprite that displays the symbol's texture and maintains a reference to the corresponding SymbolModel for easy access to the symbol's properties. 
 */
export class SymbolView {
    // Sprite and reference to symbol model
    private _sprite: PIXI.Sprite;
    private _model: SymbolModel;

    // Getters
    public get sprite(): PIXI.Sprite {
        return this._sprite;
    }

    public get model(): SymbolModel {
        return this._model;
    }

    // Constructor
    public constructor(model: SymbolModel, width: number, height: number) {
        this._model = model;
        this._sprite = PIXI.Sprite.from(model.texture);
        this._sprite.width = width;
        this._sprite.height = height;
    }

    /**
     * Public method to update the symbol model and refresh the sprite's texture accordingly.
     */
    public setModel(model: SymbolModel): void {
        this._model = model;
        this._sprite.texture = PIXI.Texture.from(model.texture);
    }
}