import { Reel } from './Reel';
import { Container } from 'pixi.js';
import * as PIXI from 'pixi.js';

/**
 * SlotContainer is an abstract class that serves as a base for different types of slot machine containers in the game.
 */
export abstract class SlotContainer extends PIXI.Container {
    protected _reels: Reel[];
    protected _container: Container;

    // Getters
    public get reels(): Reel[] {
        return this._reels;
    }

    public get container(): Container {
        return this._container;
    }

    // Constructor
    public constructor() {
        super();
        this._reels = [];
        this._container = new Container();
    }
}