/**
 * Represents a symbol in the slot machine game, including its name and texture.
 * This class serves as the data model for symbols used in the game, allowing for easy management and retrieval of symbol properties.
 */
export class SymbolModel {
    // Name and texture properties of the symbol
    private _name: string;
    private _texture: string;

    // Getters
    public get name(): string {
        return this._name;
    }

    public get texture(): string {
        return this._texture;
    }

    // Constructor
    public constructor(name: string, texture?: string) {
        this._name = name;
        // If texture is not provided, it defaults to an empty string
        this._texture = texture ?? '';
    }
}