import { SymbolModel } from './model/SymbolModel';

/**
 * ReelStrip represents a vertical strip of symbols in the slot machine game. 
 * It manages the sequence of symbols that appear on a reel and provides methods to access symbols based on their position in the strip.
 */
export class ReelStrip {
    private _symbols: SymbolModel[];

    // Constructor
    public constructor(symbols: SymbolModel[]) {
        this._symbols = symbols;
    }

    // Getters
    public get length(): number {
        return this._symbols.length;
    }

    /**
     * Returns the symbol at the specified index in the reel strip, using modulo to loop around the strip if the index exceeds its length.
     */
    public getSymbol(index: number): SymbolModel {
        const l = this._symbols.length;
        const i = ((index % l) + l) % l;
        return this._symbols[i];
    }

    /**
     * Returns the index of the specified symbol in the reel strip
     */
    public indexOf(symbol: SymbolModel): number {
        return this._symbols.indexOf(symbol);
    }
}