import * as PIXI from 'pixi.js';

/**
 * Button is a reusable UI component that encapsulates a PIXI.Graphics object to create interactive buttons in the game.
 */
export class Button {
    public view: PIXI.Graphics;

    /**
     * Constructor
     * It initializes the PIXI.Graphics object, sets up interactivity, and applies a custom drawing function if provided.
     */
    constructor(onClick: () => void, draw?: (graphics: PIXI.Graphics) => void) {
        this.view = new PIXI.Graphics();
        this.view.eventMode = 'static';
        this.view.cursor = 'pointer'; // Set the cursor to a pointer when hovering over the sprite
        this.view.on('pointerdown', onClick);
        if (draw) {
            draw(this.view);
        }
    }
}