import * as PIXI from 'pixi.js';
import { EventEmitter } from 'events';
import { Scene } from './Scene';
import { Button } from '../ui/Button';

export const STAGE_END_CONTINUE_EVENT = 'continue';

/**
 * StageEndScene is shown when a stage's spin count is exhausted.
 * It displays the final results for the completed stage and sends the player back to the lobby.
 * GameManager calls show() with the stage results, then listens to onReturn to handle the transition.
 */
export class StageEndScene extends Scene {
    // Event emitter for the return button — GameManager subscribes to trigger lobby transition
    private _onContinue: EventEmitter = new EventEmitter();
    // Result display text elements — populated by show() when the stage ends
    private _spinsText: PIXI.Text = null!;
    private _scoreText: PIXI.Text = null!;

    // Getters
    public get onContinue(): EventEmitter {
        return this._onContinue;
    }

    // Constructor
    public async init(): Promise<void> {
        this._buildUI();
        this._updateAnchor();
    }

    /**
     * Populates the results display with the completed stage data and makes the scene visible.
     * Called by GameManager immediately after the stage ends.
     */
    public show(spinCount: number, totalWin: number): void {
        this._spinsText.text = `Survived: ${spinCount} spins`;
        this._scoreText.text = `Score: ${totalWin.toFixed(2)}`;
        this.visible = true;
    }

    /**
     * Hides the scene. Called by GameManager when transitioning back to the lobby.
     */
    public hide(): void {
        this.visible = false;
    }

    /**
     * Builds the stage end UI — background, header, result displays, and return button.
     */
    private _buildUI(): void {
        const bg = new PIXI.Graphics().rect(-280, -220, 560, 440).fill({ color: 0x000000, alpha: 0.9 });
        this._container.addChild(bg);

        const header = new PIXI.Text({
            text: 'Stage Complete',
            style: new PIXI.TextStyle({ fill: 0xffffff, fontSize: 32, fontWeight: 'bold', align: 'center' })
        });
        header.anchor.set(0.5);
        header.position.set(0, -150);
        this._container.addChild(header);

        // Result text elements — content set by show() when stage ends
        this._spinsText = this._makeResultText(0, -60);
        this._scoreText = this._makeResultText(0, -10);

        // Continue button — emits STAGE_END_CONTINUE_EVENT for GameManager to trigger relic selection
        const button = new Button(() => {
            this._onContinue.emit(STAGE_END_CONTINUE_EVENT);
        }, (g) => {
            g.rect(-110, -28, 220, 56).fill(0x333333);
            g.rect(-110, -28, 220, 56).stroke({ color: 0x888888, width: 1 });
            const label = new PIXI.Text({
                text: 'Continue',
                style: new PIXI.TextStyle({ fill: 0xffffff, fontSize: 20 })
            });
            label.anchor.set(0.5);
            g.addChild(label);
        });
        button.view.position.set(0, 100);
        this._container.addChild(button.view);
    }

    /**
     * Creates a styled result text element and adds it to the container at the given position.
     */
    private _makeResultText(x: number, y: number): PIXI.Text {
        const t = new PIXI.Text({
            text: '',
            style: new PIXI.TextStyle({ fill: 0xdddddd, fontSize: 22, align: 'center' })
        });
        t.anchor.set(0.5);
        t.position.set(x, y);
        this._container.addChild(t);
        return t;
    }
}
