import * as PIXI from 'pixi.js';

/**
 * A simple TextBox class that extends PIXI.Container. It consists of a background and a text element.
 */
export class TextBox extends PIXI.Container {
    protected _background: PIXI.Graphics;
    protected _text: PIXI.Text;

    // Setters
    public set text(value: string) {
        this._text.text = value;
        this.centerText();
    }

    // Constructor
    public constructor(text: string, width: number, height: number) {
        super();
        this._background = this._drawBackground(width, height);
        this._text = this._createText(text);
        this.centerText();
        this.addChild(this._background);
        this.addChild(this._text);
    }

    // Public method to center the text within the background
    public centerText(): void {
        this._text.x = this._background.width / 2;
        this._text.y = this._background.height / 2;
    }

    // Draw the background of the text box
    private _drawBackground(width: number, height: number): PIXI.Graphics {
        // Draw background
        const background = new PIXI.Graphics();
        background.rect(0, 0, width, height).fill(0x000000);
        // Border
        background.setStrokeStyle({ width: 2, color: 0x000000 }).rect(0, 0, width, height);
        return background;
    }

    // Create the text element
    private _createText(text: string): PIXI.Text {
        // Text
        const textObj = new PIXI.Text({
            text: text,
            style: new PIXI.TextStyle({
                fontFamily: 'Arial',
                fontSize: 14,
                fill: 0xffffff,
                align: 'center',
                wordWrap: true,
            })
        });
        textObj.anchor.set(0.5);
        return textObj;
    }
}