import * as PIXI from 'pixi.js';

/**
 * The Scene class serves as a base class for different scenes in the game, such as the game scene and UI scene. 
 * It provides common functionality for managing a container and anchor point, and defines an abstract init method that must be implemented by subclasses to handle scene-specific initialization logic.
 */
export abstract class Scene extends PIXI.Container {
    // Container for all scene elements
    protected _container: PIXI.Container = new PIXI.Container();
    // Anchor point for positioning the scene
    protected _anchor: PIXI.Point = new PIXI.Point(0.5, 0.5);

    // Getters
    public get anchor(): PIXI.Point {
        return this._anchor;
    }

    public get container(): PIXI.Container {
        return this._container;
    }

    // Constructor
    public constructor() {
        super();
        this.addChild(this._container);
        this.anchor.set(0.5);
    }

    // Public method to set position of the scene based on the anchor point
    public setPosition(x: number, y: number): void {
        this._updateAnchor();
        this._container.position.set(x, y);
    }

    // Updates the anchor point of the container based on the current bounds and the specified anchor values.
    protected _updateAnchor(): void {
        const bounds = this._container.getLocalBounds();
        this._container.pivot.set(bounds.x + bounds.width * this._anchor.x, bounds.y + bounds.height * this._anchor.y);
    }

    abstract init(): Promise<void>;
}