/**
 * Defines the possible states of the slot game, where only one state can be active
 */
export enum GameState {
    LOBBY,
    IDLE,
    SPIN_START,
    SPINNING,
    WAITING_FOR_MANUAL_STOP,
    NUDGE,
    SPIN_END,
    SHOW_WIN,
    STAGE_END
}

/**
 * Implements a state machine to manage the different states of the game.
 * Provides methods to transition between states and ensures that the game logic is executed correctly based on the current state.
 */
export class GameStateMachine {
    // Single source of truth for the current game state
    private _currentState: GameState;

    // Getters
    public get currentState(): GameState {
        return this._currentState;
    }

    /**
     * Initializes the game state machine to the IDLE state when an instance is created.
     */
    public constructor() {
        this._currentState = GameState.LOBBY;
    }

    /**
     * Attempts to transition to a new game state.
     */
    public async tryGoToState(state: GameState): Promise<void> {
        // Add validation logic here if needed
        if (this._currentState === state) {
            return;
        } else if (state === GameState.IDLE && this._currentState !== GameState.LOBBY && this._currentState !== GameState.SHOW_WIN) {
            return Promise.reject(new Error(`Cannot transition to IDLE from ${this._currentState}`));
        } else if (state === GameState.SPIN_START && this._currentState !== GameState.IDLE) {
            return Promise.reject(new Error(`Cannot transition to SPIN_START from ${this._currentState}`));
        } else if (state === GameState.SPINNING && this._currentState !== GameState.SPIN_START) {
            return Promise.reject(new Error(`Cannot transition to SPINNING from ${this._currentState}`));
        } else if (state === GameState.WAITING_FOR_MANUAL_STOP && this._currentState !== GameState.SPINNING) {
            return Promise.reject(new Error(`Cannot transition to WAITING_FOR_MANUAL_STOP from ${this._currentState}`));
        } else if (state === GameState.NUDGE && this._currentState !== GameState.WAITING_FOR_MANUAL_STOP) {
            return Promise.reject(new Error(`Cannot transition to NUDGE from ${this._currentState}`));
        } else if (state === GameState.SPIN_END && this._currentState !== GameState.NUDGE) {
            return Promise.reject(new Error(`Cannot transition to SPIN_END from ${this._currentState}`));
        } else if (state === GameState.SHOW_WIN && this._currentState !== GameState.SPIN_END) {
            return Promise.reject(new Error(`Cannot transition to SHOW_WIN from ${this._currentState}`));
        } else if (state === GameState.STAGE_END && this._currentState !== GameState.IDLE) {
            return Promise.reject(new Error(`Cannot transition to STAGE_END from ${this._currentState}`));
        } else if (state === GameState.LOBBY && this._currentState !== GameState.STAGE_END) {
            return Promise.reject(new Error(`Cannot transition to LOBBY from ${this._currentState}`));
        }
        await this._goToState(state);
    }

    /**
     * Transitions to a new game state.
     */
    private async _goToState(state: GameState): Promise<void> {
        await this._stateMachine(state);
    }

    /**
     * Handles the logic for transitioning between game states. This method can be expanded to include any necessary logic that should occur during each state transition.
     */
    private async _stateMachine(state: GameState): Promise<void> {
        switch (state) {
            case GameState.LOBBY:
                return this.handleLobby();
            case GameState.IDLE:
                return this.handleIdle();
            case GameState.SPIN_START:
                return this.handleSpinStart();
            case GameState.SPINNING:
                return this.handleSpinning();
            case GameState.WAITING_FOR_MANUAL_STOP:
                return this.handleWaitingForManualStop();
            case GameState.NUDGE:
                return this.handleNudge();
            case GameState.SPIN_END:
                return this.handleSpinEnd();
            case GameState.SHOW_WIN:
                return this.handleShowWin();
            case GameState.STAGE_END:
                return this.handleStageEnd();
            default:
                return Promise.reject(new Error(`Unknown game state: ${state}`));
        }
    }

    private handleLobby(): Promise<void> {
        this._currentState = GameState.LOBBY;
        return Promise.resolve();
    }

    /**
     * Handles the logic for the IDLE state.
     */
    private handleIdle(): Promise<void> {
        // Set current state to IDLE and return
        this._currentState = GameState.IDLE;
        return Promise.resolve();
    }

    /**
     * Handles the logic for the SPIN_START state and transitions to the SPINNING state.
     */
    private handleSpinStart(): Promise<void> {
        // Set current state to SPIN_START and return next state
        this._currentState = GameState.SPIN_START;
        return this._goToState(GameState.SPINNING);
    }

    /**
     * Handles the logic for the SPINNING state and transitions to the SPIN_END state.
     */
    private handleSpinning(): Promise<void> {
        // Set current state to SPINNING and return next state
        this._currentState = GameState.SPINNING;
        return this._goToState(GameState.WAITING_FOR_MANUAL_STOP);
    }

    /**
     * Handles the logic for the WAITING_FOR_MANUAL_STOP state and transitions to the SPIN_END state.
     */
    private handleWaitingForManualStop(): Promise<void> {
        // Set current state to WAITING_FOR_MANUAL_STOP and return next state
        this._currentState = GameState.WAITING_FOR_MANUAL_STOP;
        return Promise.resolve();
    }

    /**
     * Handles the NUDGE state. Waits for NudgeController to resolve the window before proceeding.
     */
    private handleNudge(): Promise<void> {
        this._currentState = GameState.NUDGE;
        return Promise.resolve();
    }

    /**
     * Handles the logic for the SPIN_END state and transitions to the SHOW_WIN state.
     */
    private handleSpinEnd(): Promise<void> {
        // Set current state to SPIN_END and return next state
        this._currentState = GameState.SPIN_END;
        return this._goToState(GameState.SHOW_WIN);
    }

    /**
     * Handles the logic for the SHOW_WIN state and transitions to the IDLE state.
     */
    private handleShowWin(): Promise<void> {
        this._currentState = GameState.SHOW_WIN;
        return this._goToState(GameState.IDLE);
    }

    /**
     * Handles the logic for the STAGE_END state. Spins are blocked here until
     * the stage is reset and a new one started (which returns to IDLE).
     */
    private handleStageEnd(): Promise<void> {
        this._currentState = GameState.STAGE_END;
        return Promise.resolve();
    }
}