import { EventEmitter } from 'events';
import { SpinController } from '../spin/SpinController';

/**
 * StageController tracks the player's progress through a stage — spins elapsed and
 * accumulated score. It no longer owns the end condition; PressureController fires
 * onStageEnded when corruption fills. StageController's spin count remains useful
 * as a survival metric displayed to the player and recorded at run end.
 */
export class StageController {
    // Spin tracking — elapsed count only, no max
    private _spinCount: number = 0;
    // Score tracking, accumulated via addWin() after each spin evaluation
    private _totalWin: number = 0;
    // Whether the stage is currently accepting spins
    private _isActive: boolean = false;
    // Events — GameManager subscribes to forward updates to the UI
    private _onCountChanged: EventEmitter = new EventEmitter();
    private _onWinChanged: EventEmitter = new EventEmitter();

    // Getters
    public get spinCount(): number { return this._spinCount; }
    public get totalWin(): number { return this._totalWin; }
    public get isActive(): boolean { return this._isActive; }
    public get onCountChanged(): EventEmitter { return this._onCountChanged; }
    public get onWinChanged(): EventEmitter { return this._onWinChanged; }

    // Constructor
    constructor(spinController: SpinController) {
        spinController.onSpinComplete.on('complete', () => this._handleSpinComplete());
    }

    /**
     * Begins a new stage. Resets count and score, marks the stage active.
     */
    public startStage(): void {
        this._spinCount = 0;
        this._totalWin = 0;
        this._isActive = true;
        this._onCountChanged.emit('changed', this._spinCount);
        this._onWinChanged.emit('changed', this._totalWin);
    }

    /**
     * Resets stage state without starting a new one.
     */
    public resetStage(): void {
        this._spinCount = 0;
        this._totalWin = 0;
        this._isActive = false;
        this._onCountChanged.emit('changed', this._spinCount);
        this._onWinChanged.emit('changed', this._totalWin);
    }

    /**
     * Accumulates a win amount for the current stage. No-ops when not active.
     */
    public addWin(amount: number): void {
        if (!this._isActive) return;
        this._totalWin += amount;
        this._onWinChanged.emit('changed', this._totalWin);
    }

    /**
     * Increments the spin count and fires the update event.
     */
    private _handleSpinComplete(): void {
        if (!this._isActive) return;
        this._spinCount++;
        this._onCountChanged.emit('changed', this._spinCount);
    }
}
