import Renderer from '../renderer/Renderer';
import { Scene } from './Scene';
import * as PIXI from 'pixi.js';
import { SpinButton } from '../ui/SpinButton';
import { EventEmitter } from 'events';
import { TextBox } from '../ui/TextBox';
import { SpinData } from '../data/DataManager';
import { Button } from '../ui/Button';
import { GameState, GameStateMachine } from '../game/GameStateMachine';
import { SPIN_EVENT, STOP_COLUMN_EVENT } from '../Constants';
import { RelicData } from '../relic/RelicManager';

// Constants
const NO_TEST_DATA_TEXT = 'No Test Data';

/**
 * The UIScene class is responsible for managing the user interface elements of the game, including both player-facing UI and debug UI. 
 * It extends the base Scene class and implements the init method to set up the necessary UI components. 
 * The class provides functionality for selecting test data for spins and emitting spin events when the spin button is pressed.
 */
export class UIScene extends Scene {
    // Renderer reference 
    private _renderer: Renderer;
    // State Machine Reference
    protected _gameStateMachine: GameStateMachine;
    // UI Containers
    private _debugUIContainer: PIXI.Container = new PIXI.Container();
    private _playerUIContainer: PIXI.Container = new PIXI.Container();
    // Test data box
    private _testDataTextBox: TextBox = null!;
    private _testDataKeys: string[] = [];
    private _currentTestDataIndex: number = 0;
    // Spin event emitter
    private _sendSpin: EventEmitter = new EventEmitter();
    // Stop event emitter
    private _sendStop: EventEmitter = new EventEmitter();

    // Getters
    public get debugUIContainer(): PIXI.Container {
        return this._debugUIContainer;
    }

    public get playerUIContainer(): PIXI.Container {
        return this._playerUIContainer;
    }

    public get spin(): EventEmitter {
        return this._sendSpin;
    }

    public get stop(): EventEmitter {
        return this._sendStop;
    }

    // Constructor
    public constructor(renderer: Renderer, gameStateMachine: GameStateMachine, spinData?: Record<string, SpinData>) {
        super();
        this._renderer = renderer;
        this._gameStateMachine = gameStateMachine;

        // Initialize test data keys for selection, include a default option if no test data is provided
        if (spinData) {
            this._testDataKeys = [NO_TEST_DATA_TEXT, ...Object.keys(spinData)];
        } else {
            this._testDataKeys = [NO_TEST_DATA_TEXT];
        }
    }

    /**
     * Initializes the UI scene by setting up the player UI and debug UI components. 
     */
    public async init(): Promise<void> {
        await this._loadAssets();
        // Anchor the UI scene to the center of the screen and add the debug and player UI containers to the main container
        this.anchor.set(0.5);
        this._container.addChild(this._debugUIContainer);
        this._container.addChild(this._playerUIContainer);
        // Initialize UI components
        this._initializePlayerUI();
        this._initializeDebugUI();

        this._updateAnchor();
    }

    // Spin counter display
    private _spinCountBox: TextBox = null!;
    // Total win display
    private _totalWinBox: TextBox = null!;
    // Pressure bar — background track and filled indicator
    private _pressureTrack: PIXI.Graphics = null!;
    private _pressureFill: PIXI.Graphics = null!;
    // Dimensions of the pressure bar
    private static readonly PRESSURE_BAR_WIDTH = 120;
    private static readonly PRESSURE_BAR_HEIGHT = 10;
    // Relic tray — small icon tiles showing active relics
    private _relicTray: PIXI.Container = new PIXI.Container();
    private _relicTiles: Map<string, PIXI.Graphics> = new Map();
    private static readonly RELIC_TILE_SIZE = 20;
    private static readonly RELIC_TILE_GAP = 6;

    /**
     *  Initializes the player UI components
     */
    private _initializePlayerUI(): void {
        this._initializeSpinButton();
        this._initializeSpinCountBox();
        this._initializeTotalWinBox();
        this._initializePressureBar();
        this._initializeRelicTray();
    }

    /**
     * Updates the spin counter display. Called by GameManager after each spin completes.
     */
    public updateSpinCount(count: number): void {
        this._spinCountBox.text = `Spins: ${count}`;
    }

    public updateTotalWin(total: number): void {
        this._totalWinBox.text = `Score: ${total.toFixed(2)}`;
    }

    /**
     * Initializes the debug UI components
     */
    private _initializeDebugUI(): void {
        this._initializeTestDataTextBox();
        this._initializeTestDataButtons();
    }

    /**
     * Initializes the spin counter text box displayed above the spin button.
     */
    private _initializeSpinCountBox(): void {
        const box = new TextBox('Spins: 0', 130, 40);
        this._playerUIContainer.addChild(box);
        box.position.set(-60, -60);
        this._spinCountBox = box;
    }

    private _initializeTotalWinBox(): void {
        const box = new TextBox('Score: 0.00', 120, 40);
        this._playerUIContainer.addChild(box);
        box.position.set(-60, -110);
        this._totalWinBox = box;
    }

    /**
     * Builds the pressure bar — a fixed-size track with a filled indicator on top.
     * Positioned above the spin count box.
     */
    private _initializePressureBar(): void {
        const w = UIScene.PRESSURE_BAR_WIDTH;
        const h = UIScene.PRESSURE_BAR_HEIGHT;
        const x = -60;
        const y = -165;

        // Dark track (background)
        this._pressureTrack = new PIXI.Graphics().rect(x, y, w, h).fill(0x222222);
        this._playerUIContainer.addChild(this._pressureTrack);

        // Colored fill — drawn at zero width initially, redrawn by updatePressure()
        this._pressureFill = new PIXI.Graphics();
        this._playerUIContainer.addChild(this._pressureFill);
        this._drawPressureFill(0);
    }

    /**
     * Redraws the pressure fill to match the given ratio (0..1).
     * Color shifts from green through amber to red as pressure rises.
     */
    private _drawPressureFill(ratio: number): void {
        const w = UIScene.PRESSURE_BAR_WIDTH;
        const h = UIScene.PRESSURE_BAR_HEIGHT;
        const x = -60;
        const y = -165;
        const fillW = Math.max(0, Math.min(1, ratio)) * w;
        const color = ratio < 0.5 ? 0x44bb44 : ratio < 0.75 ? 0xddaa22 : 0xcc3333;
        this._pressureFill.clear();
        if (fillW > 0) {
            this._pressureFill.rect(x, y, fillW, h).fill(color);
        }
    }

    /**
     * Updates the pressure bar fill. Called by GameManager each time pressure changes.
     */
    public updatePressure(ratio: number): void {
        this._drawPressureFill(ratio);
    }

    /**
     * Positions the relic tray just above the pressure bar. Empty until relics are added.
     */
    private _initializeRelicTray(): void {
        this._relicTray.position.set(-60, -182);
        this._playerUIContainer.addChild(this._relicTray);
    }

    /**
     * Adds a relic icon tile to the tray. Called by GameManager after the player picks a relic.
     */
    public addRelicToTray(relic: RelicData): void {
        const s = UIScene.RELIC_TILE_SIZE;
        const gap = UIScene.RELIC_TILE_GAP;
        const x = this._relicTiles.size * (s + gap);
        const tile = new PIXI.Graphics()
            .rect(0, 0, s, s)
            .fill(relic.color)
            .rect(0, 0, s, s)
            .stroke({ color: 0xd4af37, width: 1 });
        tile.position.set(x, 0);
        this._relicTray.addChild(tile);
        this._relicTiles.set(relic.id, tile);
    }

    /**
     * Briefly pulses a relic tile gold to signal its effect just fired.
     */
    public pulseRelic(id: string): void {
        const tile = this._relicTiles.get(id);
        if (!tile) return;
        tile.alpha = 0.4;
        const start = performance.now();
        const restore = (now: number) => {
            const t = Math.min((now - start) / 300, 1);
            tile.alpha = 0.4 + 0.6 * t;
            if (t < 1) requestAnimationFrame(restore);
        };
        requestAnimationFrame(restore);
    }

    /**
     * Initializes the spin button, sets up its click handler to emit a spin event with the selected test data, and defines a custom draw function to load and display the button texture.
     */
    private _initializeSpinButton(): void {
        const button = new SpinButton(60, () => {
            if (this._gameStateMachine.currentState === GameState.IDLE) {
                console.log('Spin button clicked, emitting spin event');
                // Emit the selected test data, or no test data, when the spin button is clicked
                const selected = this._testDataKeys[this._currentTestDataIndex];
                this._sendSpin.emit(SPIN_EVENT, selected);
            } else if (this._gameStateMachine.currentState === GameState.WAITING_FOR_MANUAL_STOP) {
                console.log('Stop button clicked, emitting stop event');
                this._sendStop.emit(STOP_COLUMN_EVENT);
            }
        }, async (graphics) => {
            // Load the button texture and create a sprite, then apply a circular mask to achieve a round button appearance
            await this._renderer.loadAssets({ spinButton: './resources/assets/ui/spinButton.png' });
            const texture = PIXI.Assets.get('./resources/assets/ui/spinButton.png');
            const sprite = new PIXI.Sprite(texture);
            sprite.anchor.set(0.5);
            sprite.width = 100;
            sprite.height = 100;
            const mask = new PIXI.Graphics().circle(0, 0, 50).fill(0xffffff);
            sprite.mask = mask;
            graphics.addChild(sprite);
            graphics.addChild(mask);
        });
        // Add the button to the player UI container and position it
        this._playerUIContainer.addChild(button.view);
        button.view.position.set(0, 0);
        const bounds = this._playerUIContainer.getLocalBounds();
        this._playerUIContainer.pivot.set(
            bounds.width / 2,
            bounds.height / 2
        );
    }

    /**
     * Initializes the test data text box to display the currently selected test data key, or a default message if no test data is available. 
     */
    private _initializeTestDataTextBox(): void {
        // Create a text box to display the currently selected test data key, or a default message if no test data is available
        const initialKey = this._testDataKeys[0] ?? NO_TEST_DATA_TEXT;
        const testDataTextBox = new TextBox(`Test Data: ${initialKey}`, 100, 100);
        // Add the text box to the debug UI container and position it
        this._debugUIContainer.addChild(testDataTextBox);
        testDataTextBox.position.set(0, 0);
        this._testDataTextBox = testDataTextBox;
    }

    /**
     * Updates the test data text box to reflect the currently selected test data key. 
     * If no test data is available, it displays a default message. 
     */
    private _updateSelectedTestData(): void {
        // If there is no test data, display a default message
        if (this._testDataKeys.length === 0) {
            this._testDataTextBox.text = `Test Data: ${NO_TEST_DATA_TEXT}`;
            return;
        }
        // Update the text box to show the currently selected test data key
        const currentKey = this._testDataKeys[this._currentTestDataIndex];
        this._testDataTextBox.text = `Test Data: ${currentKey}`;
    }

    /**
     * Initializes the buttons for selecting test data. 
     * It creates left and right arrow buttons that allow the user to cycle through the available test data keys. 
     * When a button is clicked, it updates the current test data index and refreshes the displayed selected test data key in the text box.
     */
    private _initializeTestDataButtons(): void {
        // Draw arrows
        const leftArrow = (graphic: PIXI.Graphics) => {
            graphic.poly([20, 0, 0, 10, 20, 20]).fill(0xffffff);
        };
        const rightArrow = (graphic: PIXI.Graphics) => {
            graphic.poly([0, 0, 20, 10, 0, 20]).fill(0xffffff);
        };
        // Create buttons using arrows
        const leftButton = new Button(() => {
            this._currentTestDataIndex--;
            if (this._currentTestDataIndex < 0) {
                this._currentTestDataIndex = this._testDataKeys.length - 1;
            }
            this._updateSelectedTestData();
        }, leftArrow);
        const rightButton = new Button(() => {
            this._currentTestDataIndex++;
            if (this._currentTestDataIndex >= this._testDataKeys.length) {
                this._currentTestDataIndex = 0;
            }
            this._updateSelectedTestData();
        }, rightArrow);
        // Add buttons to debug UI container and position them on either side of the test data text box
        this._debugUIContainer.addChild(leftButton.view);
        this._debugUIContainer.addChild(rightButton.view);
        const textBox = this._testDataTextBox;
        const centerY = textBox.y + textBox.height / 2;
        leftButton.view.position.set(textBox.x - leftButton.view.width - 10, centerY - leftButton.view.height / 2);
        rightButton.view.position.set(textBox.x + textBox.width + 10, centerY - rightButton.view.height / 2);
    }

    private async _loadAssets(): Promise<void> {
        await this._renderer.loadAssets({ spinButton: './resources/assets/ui/spinButton.png' });
    }
}