import { EventEmitter } from 'events';
import relicsConfig from '../config/relics.config.json';

export type RelicEffectType = 'win_multiplier' | 'pressure_reduction' | 'nudge_extension' | 'threshold_shift' | 'first_win_double';

export interface RelicEffect {
    type: RelicEffectType;
    value: number;
}

export interface RelicData {
    id: string;
    name: string;
    description: string;
    color: number;
    effect: RelicEffect;
}

/**
 * RelicManager tracks temple relics carried across stages within a session.
 * Provides effect hooks queried by PressureController, NudgeController, and GameManager.
 * Emits 'activated' with the relic id whenever an effect fires, for UI pulse feedback.
 */
export class RelicManager {
    private _allRelics: RelicData[] = relicsConfig.relics as RelicData[];
    private _activeRelics: RelicData[] = [];
    private _firstWinUsed: boolean = false;
    private _onRelicActivated: EventEmitter = new EventEmitter();

    public get activeRelics(): RelicData[] { return [...this._activeRelics]; }
    public get onRelicActivated(): EventEmitter { return this._onRelicActivated; }

    /**
     * Returns up to `count` random relics not already active this session.
     */
    public getRandomOptions(count: number): RelicData[] {
        const available = this._allRelics.filter(r => !this._activeRelics.some(a => a.id === r.id));
        return [...available].sort(() => Math.random() - 0.5).slice(0, count);
    }

    public addRelic(relic: RelicData): void {
        this._activeRelics.push(relic);
    }

    /**
     * Resets per-stage state (e.g. first-win flags). Does NOT clear the relic list.
     * Call at the start of each stage.
     */
    public onStageStart(): void {
        this._firstWinUsed = false;
    }

    /**
     * Applies all win-modifying relics to `rawWin` and returns the final amount.
     * Emits 'activated' for each relic that fires so the UI tray can pulse it.
     */
    public processWin(rawWin: number): number {
        if (rawWin <= 0) return 0;
        let modified = rawWin;

        const firstWinRelic = this._activeRelics.find(r => r.effect.type === 'first_win_double');
        if (firstWinRelic && !this._firstWinUsed) {
            modified *= 2;
            this._firstWinUsed = true;
            this._onRelicActivated.emit('activated', firstWinRelic.id);
        }

        for (const relic of this._activeRelics.filter(r => r.effect.type === 'win_multiplier')) {
            modified *= relic.effect.value;
            this._onRelicActivated.emit('activated', relic.id);
        }

        return Math.floor(modified);
    }

    /**
     * Multiplier applied to pressure increment each spin. < 1 means slower corruption.
     */
    public getPressureMultiplier(): number {
        return this._activeRelics
            .filter(r => r.effect.type === 'pressure_reduction')
            .reduce((acc, r) => acc * (1 - r.effect.value), 1);
    }

    /**
     * Extra seconds added to the nudge window duration.
     */
    public getNudgeWindowBonus(): number {
        return this._activeRelics
            .filter(r => r.effect.type === 'nudge_extension')
            .reduce((acc, r) => acc + r.effect.value, 0);
    }

    /**
     * Percentage points added to each threshold before it can fire.
     * e.g. value 15 shifts the 50% threshold to 65%.
     */
    public getThresholdShift(): number {
        return this._activeRelics
            .filter(r => r.effect.type === 'threshold_shift')
            .reduce((acc, r) => acc + r.effect.value, 0);
    }
}
