import * as PIXI from 'pixi.js';
import { BaseGameScene } from '../scenes/BaseGameScene';
import { UIScene } from '../scenes/UIScene';

// Constants
const UI_SPACING_PORTRAIT = 60;
const UI_INNER_SPACING = 40;
const UI_OUTER_SPACING = 1;
const PORTRAIT_SPIN_BUTTON_X = 50;
const PORTRAIT_SPIN_BUTTON_Y = 100;

/**
 * LayoutContext defines the expected form of information regarding layout
 * Size and orientation are the main factors that influence how the layout is applied
 */
interface LayoutContext {
    screenWidth: number;
    screenHeight: number;
    isPortrait: boolean;
}

/**
 * LayoutManager is responsible for calculating and applying the layout of scenes based on the current screen size and orientation.
 */
export class LayoutManager {
    private _app: PIXI.Application;
    private _root: PIXI.Container;
    private _gameScene: BaseGameScene;
    private _uiScene: UIScene;

    // Contructor
    constructor(app: PIXI.Application, root: PIXI.Container, gameScene: BaseGameScene, uiScene: UIScene) {
        this._app = app;
        this._root = root;
        this._gameScene = gameScene;
        this._uiScene = uiScene;
    }

    /**
     * Public method to update layout
     */
    public layout(): void {
        // Create context based on current screen size and orientation and apply layout
        const layoutContext: LayoutContext = {
            screenWidth: this._app.screen.width,
            screenHeight: this._app.screen.height,
            isPortrait: this._app.screen.height > this._app.screen.width
        };
        this._applyLayout(layoutContext);
    }

    /**
     * Takes the context and applies the layout accordingly
     */
    private _applyLayout(layoutContext: LayoutContext): void {
        // Reset scale and position before applying new layout
        this._root.scale.set(1);
        this._root.position.set(0, 0);

        this._gameScene.slotContainer.layout();

        // Get game scene bounds and apply layout based on orientation
        const bounds = this._gameScene.slotBounds;
        if (layoutContext.isPortrait) {
            this._layoutPortrait(layoutContext, bounds);
        } else {
            this._layoutLandscape(layoutContext, bounds);
        }
    }

    /**
     * Landscape orientation needs special handling to position the UI on the sides of the game scene
     */
    private _layoutLandscape(layoutContext: LayoutContext, bounds: PIXI.Bounds): void {
        // Get sizes of left and right UI panels
        const leftUiBounds = this._uiScene.debugUIContainer.getLocalBounds();
        const rightUiBounds = this._uiScene.playerUIContainer.getLocalBounds();
        // Calculate ideal width of the whole layout (game + UI) based on the sizes of each component and spacing requirements
        const contentWidth = (leftUiBounds.width - leftUiBounds.x) + UI_INNER_SPACING + bounds.width + UI_INNER_SPACING + (rightUiBounds.width - rightUiBounds.x);
        // In landscape, the height of the layout is determined by the tallest component (game scene or either UI panel)
        const contentHeight = Math.max(bounds.height, leftUiBounds.height, rightUiBounds.height);
        // Add outer spacing to width
        const baseWidth = contentWidth + UI_OUTER_SPACING * 2;
        // In landscape, the base height is just the content height
        const baseHeight = contentHeight;
        // Scale in landscape is determined by fitting the width of the whole layout (game + UI) within the screen while maintaining aspect ratio
        // Height is less of a constraint in landscape since the layout is wider than it is taller, so we prioritize fitting to width
        const scale = Math.min(layoutContext.screenWidth / baseWidth, layoutContext.screenHeight / baseHeight);
        this._root.scale.set(scale);
        // Center the whole layout within the screen
        this._root.position.set(
            (layoutContext.screenWidth - baseWidth * scale) / 2,
            (layoutContext.screenHeight - baseHeight * scale) / 2
        );
        // Using the width of object from left to right, position each element with the required spacing in between
        let x = UI_OUTER_SPACING;
        const centerY = baseHeight / 2;
        // Left UI Container
        x += (leftUiBounds.width - leftUiBounds.x) / 2;
        this._uiScene.debugUIContainer.position.set(x - leftUiBounds.x, centerY);
        x += (leftUiBounds.width - leftUiBounds.x) / 2 + UI_INNER_SPACING;
        // Slot game is centered
        const gameWidth = bounds.width;
        x += gameWidth / 2;
        // Position scenes based on calculated x and centerY, then layout internal elements of game scene (slots, etc.)
        this._gameScene.setPosition(x, centerY);
        this._uiScene.setPosition(x, centerY);
        this._gameScene.slotContainer.layout();
        // Right UI Container
        x += gameWidth / 2 + UI_INNER_SPACING;
        x += (rightUiBounds.width - rightUiBounds.x) / 2;
        this._uiScene.playerUIContainer.position.set(x - rightUiBounds.x, centerY);
    }

    /**
     * Layout the scene for portrait, where UI is positioned above and below the game scene.
     */
    private _layoutPortrait(layoutContext: LayoutContext, bounds: PIXI.Bounds): void {
        // In portrait, the width of the layout is determined by the game scene since the UI is stacked vertically and can be narrower than the game scene
        const totalHeight = bounds.height + (UI_SPACING_PORTRAIT * 2);
        const totalWidth = bounds.width;
        // Scale in portrait is determined by fitting the height of the whole layout (game + UI) within the screen while maintaining aspect ratio
        const scale = Math.min(
            layoutContext.screenWidth / totalWidth,
            layoutContext.screenHeight / totalHeight
        );
        this._root.scale.set(scale);
        // Center the whole layout within the screen
        this._root.position.set(
            (layoutContext.screenWidth - totalWidth * scale) / 2,
            (layoutContext.screenHeight - totalHeight * scale) / 2
        );
        const centerX = totalWidth / 2;
        const centerY = totalHeight / 2;
        this._gameScene.setPosition(centerX, centerY);
        this._uiScene.setPosition(centerX, centerY);
        // Layout game scene elements
        this._gameScene.slotContainer.layout();
        // Position UI containers above and below the game scene with the required spacing
        const halfHeight = bounds.height / 2;
        this._uiScene.debugUIContainer.position.set(0, -halfHeight - UI_SPACING_PORTRAIT);
        this._uiScene.playerUIContainer.position.set(PORTRAIT_SPIN_BUTTON_X, halfHeight + UI_SPACING_PORTRAIT + PORTRAIT_SPIN_BUTTON_Y);
    }
}