import { GameState, GameStateMachine } from '../game/GameStateMachine';
import BaseSlotContainer from '../slot/BaseSlotContainer';
import baseSlotConfig from '../config/baseSlot.config.json';
import { ReelState } from '../slot/Reel';
import { ReelsetData, SpinData } from '../data/DataManager';
import { EventEmitter } from 'events';

/**
 * SpinController manages the spinning logic of the slot machine game, including starting and stopping spins, updating reel states, and handling spin results.
 * It interacts with the GameStateMachine to control the flow of the game and uses the BaseSlotContainer to manage the reels and their states during spins.
 * The SpinController also handles the generation of target symbols for each reel based on provided spin data or random generation when no specific data is available.
 */
export class SpinController {
    // Slot Container Reference
    protected _slotContainer: BaseSlotContainer = null!;
    // State Machine Reference
    protected _gameStateMachine: GameStateMachine;
    // Spin
    protected _isSpinning: boolean = false;
    protected _spinResult: number[] | null = null;
    protected _spinData: Record<string, any> = {};
    protected _spinIndexMap: Record<string, number> = {};
    protected _spinTimer: number = 0;
    protected _spinDuration: number;
    // Reel Targeting
    protected _reelSpinDelay: number;
    protected _targets: SpinData = {};
    protected _reelsets: ReelsetData[] = [];
    protected _activeReelset: ReelsetData | null = null;
    protected _reelsStopped: boolean[] = [];
    // Manual stop mode — when true, the auto-stop timer is suppressed and columns stop only via stopNextColumn()
    protected _manualStopMode: boolean = false;
    // Nudge gate — true while waiting for NudgeController to close its window
    protected _nudgePhaseActive: boolean = false;
    // Events
    private _onSpinComplete: EventEmitter = new EventEmitter();
    private _onAllReelsStopped: EventEmitter = new EventEmitter();

    // Getters and Setters
    public get slotContainer(): BaseSlotContainer {
        return this._slotContainer;
    }

    public set slotContainer(container: BaseSlotContainer) {
        this._slotContainer = container;
    }

    public get isSpinning(): boolean {
        return this._isSpinning;
    }

    public get spinResult(): number[] | null {
        return this._spinResult;
    }

    public get onSpinComplete(): EventEmitter {
        return this._onSpinComplete;
    }

    public get activeReelset(): ReelsetData | null {
        return this._activeReelset;
    }

    public get onAllReelsStopped(): EventEmitter {
        return this._onAllReelsStopped;
    }

    /**
     * Swaps the active reelset by ID. Takes effect on the next spin.
     * Falls back silently if the ID is not found.
     */
    public setActiveReelset(id: string): void {
        const found = this._reelsets.find(r => r.id === id);
        if (found) this._activeReelset = found;
    }

    // Constructor
    public constructor(
        stateMachine: GameStateMachine,
        reelsets: ReelsetData[],
        spinData?: Record<string, any>,
    ) {
        this._gameStateMachine = stateMachine;
        this._reelsets = reelsets;
        this._spinData = spinData ?? {};
        this._spinDuration = baseSlotConfig.baseSlotConfig.spinDuration;
        this._reelSpinDelay = baseSlotConfig.baseSlotConfig.reelSpinDelay;
        this._activeReelset = this._reelsets.length > 0 ? this._reelsets[0] : null;
    }

    /**
     * Initiates a spin with an optional spin key to determine the target symbols for each reel.
     */
    public spin(spinKey?: string) {
        console.log('SpinController: spin called with spinKey:', spinKey);
        // Cannot start a new spin if the game is not in the IDLE state
        if (this._gameStateMachine.currentState !== GameState.IDLE) {
            return;
        }
        // Transition to SPIN_START state
        this._gameStateMachine.tryGoToState(GameState.SPIN_START);
        // Start spinning
        this._isSpinning = true;
        this._spinTimer = 0;
        this._manualStopMode = false;
        this._nudgePhaseActive = false;
        this._reelsStopped = new Array(this._slotContainer.reels.length).fill(false);
        this._slotContainer.reels.forEach((reel) => reel.spin());

        // Determine targets for each reel based on spin data or generate randomly if no data is available
        if (spinKey && this._spinData[spinKey]) {
            const data = this._spinData[spinKey];
            const datasetKeys = Object.keys(data);
            if (datasetKeys.length > 0) {
                const dataset = data[datasetKeys[0]];
                const spinKeys = Object.keys(dataset);
                if (spinKeys.length > 0) {
                    // Use spin index map to ensure we cycle through available spin data for the given spin key
                    if (this._spinIndexMap[spinKey] === undefined) {
                        this._spinIndexMap[spinKey] = 0;
                    }
                    const index = this._spinIndexMap[spinKey] % spinKeys.length;
                    const chosen = dataset[spinKeys[index]];
                    this._spinIndexMap[spinKey]++;
                    // Convert the chosen array of target indices into the format expected by the reels and store it in the _targets property
                    this._targets = this._convertArrayToTargets(chosen);
                } else {
                    this._targets = this._generateTargets();
                }
            } else {
                this._targets = this._generateTargets();
            }
        } else {
            this._targets = this._generateTargets();
        }
    }

    /**
     * Update method to be called on each game tick, which updates the state of the reels during a spin and checks if they should stop based on the configured spin duration and delay for each reel.
     */
    public update(delta: number): void {
        // Always update the slot container so nudge slide animations run during the NUDGE phase
        this._slotContainer.update(delta);

        if (!this._isSpinning) {
            return;
        }

        this._spinTimer += delta;
        // Auto-stop is suppressed when manual stop mode is active — columns stop only via stopNextColumn() in that case.
        if (!this._manualStopMode) {
            // Check if each reel should stop based on the elapsed spin time and the configured spin duration and delay for each reel.
            // If a reel should stop, calculate the target notch index and set the planned stops for that reel to ensure it lands on the correct symbol.
            this._slotContainer.reels.forEach((reel, index) => {
                const stopTime = this._spinDuration + index * this._reelSpinDelay;
                if (
                    this._spinTimer >= stopTime &&
                    !this._reelsStopped[index]
                ) {
                    // Calculate target notch index and set planned stops for the reel.
                    const key = index.toString();
                    const target = this._targets[key]?.[0] ?? 0;
                    const strip = this._activeReelset!.reels[index];
                    const stripLength = strip.length;
                    // Must cycle through every view (viewCount = visibleRows + 2 buffer) so that
                    // TOP/MID/BOT all receive correct sequential strip values — fewer steps leave
                    // some visible rows showing free-spin symbols that won't match evaluation.
                    const totalSteps = reel.viewCount;
                    // Sequence must decrease so that strip[target] lands at the TOP visible row.
                    // The last value consumed is target-1 (above-visible), leaving strip[target] at TOP.
                    const adjustedTarget = (target - 1 + stripLength) % stripLength;
                    const startIndex = (adjustedTarget + totalSteps - 1 + stripLength * 10) % stripLength;
                    const sequence: number[] = [];
                    // Generate a decreasing sequence ending at adjustedTarget (= target - 1)
                    for (let i = 0; i < totalSteps; i++) {
                        sequence.push((startIndex - i + stripLength * 10) % stripLength);
                    }
                    reel.setPlannedStops(sequence);
                    reel.stop();
                    this._reelsStopped[index] = true;
                }
            });
        }

        const allReelsIdle = this._slotContainer.reels.every(
            (reel) => reel.reelState === ReelState.IDLE,
        );

        // When all reels are idle, enter the nudge phase rather than resolving immediately.
        // NudgeController owns the window and calls resolveNudge() when it closes.
        if (allReelsIdle && !this._nudgePhaseActive) {
            this._nudgePhaseActive = true;
            this._gameStateMachine.tryGoToState(GameState.NUDGE);
            this._onAllReelsStopped.emit('stopped');
        }
    }

    /**
     * Stops the next spinning reel (left to right) by coasting one notch boundary and settling.
     * Instead of an instant snap, the reel travels at most one symbol height (≤ 0.35s) to the
     * next natural grid boundary, then stops — giving the player a smooth "lock-in" feel rather
     * than a jarring jump. Strip indices stay sequential so evaluation is always consistent.
     */
    public stopNextColumn(): void {
        // Entering manual stop mode suppresses the auto-stop timer for the remainder of this spin
        this._manualStopMode = true;
        // Find the leftmost reel that is still in the SPINNING state
        const reels = this._slotContainer.reels;
        const index = reels.findIndex((reel, i) => reel.reelState === ReelState.SPINNING && !this._reelsStopped[i]);
        if (index === -1) return;

        const reel = reels[index];
        const strip = this._activeReelset!.reels[index];
        const stripLength = strip.length;
        // Continue the natural free-spin decrement for one more step so the reel
        // coasts to the next grid boundary without changing which symbol is at each row.
        const naturalNext = (reel.currentIndex - 1 + stripLength) % stripLength;
        reel.setPlannedStops([naturalNext]);
        reel.stop();
        this._reelsStopped[index] = true;
    }

    /**
     * Called by NudgeController once the nudge window closes.
     * Collects the final reel positions, transitions to SPIN_END, and emits the spin result.
     */
    public resolveNudge(): void {
        if (!this._nudgePhaseActive) return;
        this._nudgePhaseActive = false;
        this._spinResult = this._slotContainer.reels.map(reel => reel.currentIndex);
        this._gameStateMachine.tryGoToState(GameState.SPIN_END);
        this._onSpinComplete.emit('complete', this._spinResult);
        this._stopSpin();
    }

    /**
     * Set SpinController to not spinning state
     */
    private _stopSpin() {
        this._isSpinning = false;
    }

    /**
     * Converts an array of target indices for each reel into the SpinData format expected by the reels.
     */
    private _convertArrayToTargets(targets: number[]): SpinData {
        const data: SpinData = {};
        const reelCount = this._slotContainer.reels.length;
        for (let i = 0; i < reelCount; i++) {
            let value = targets[i] ?? 0;
            if (this._activeReelset) {
                const strip = this._activeReelset.reels[i];
                const max = strip.length;
                value = ((value % max) + max) % max;
            } else {
                const max = this._slotContainer.reels[i].notchCount;
                value = ((value % max) + max) % max;
            }
            data[i.toString()] = [value];
        }
        return data;
    }

    /**
     * Generates random target indices for each reel when no specific spin data is available
     */
    private _generateTargets(): SpinData {
        const data: SpinData = {};
        this._slotContainer.reels.forEach((reel, index) => {
            const key = index.toString();
            if (this._activeReelset) {
                const strip = this._activeReelset.reels[index];
                const max = strip.length;
                data[key] = [Math.floor(Math.random() * max)];
            } else {
                data[key] = [Math.floor(Math.random() * reel.notchCount)];
            }
        });
        return data;
    }

}

export default SpinController;