import { Renderer } from '../renderer/Renderer';
import { SpinController } from '../spin/SpinController';
import { GameState, GameStateMachine } from './GameStateMachine';
import { BaseGameScene } from '../scenes/BaseGameScene';
import { UIScene } from '../scenes/UIScene';
import { LobbyScene, LOBBY_START_EVENT } from '../scenes/LobbyScene';
import { StageEndScene, STAGE_END_CONTINUE_EVENT } from '../scenes/StageEndScene';
import { RelicSelectScene, RELIC_SELECTED_EVENT } from '../scenes/RelicSelectScene';
import { RelicManager, RelicData } from '../relic/RelicManager';
import { LayoutManager } from '../renderer/LayoutManager';
import * as PIXI from 'pixi.js';
import { DataManager } from '../data/DataManager';
import { once } from 'events';
import { WinManager } from '../win/WinManager';
import winConfig from '../config/wins.config.json';
import { SPIN_EVENT, STOP_COLUMN_EVENT } from '../Constants';
import { StageController } from '../stage/StageController';
import { PressureController } from '../pressure/PressureController';
import { SkillWindowController } from '../skill/SkillWindowController';
import { NudgeController } from '../skill/NudgeController';

/**
 * The GameManager class serves as the central hub for managing the overall game flow by coordinating between different high-level components.
 * It initializes the other managers, scenes, and core components and coordinates their interactions, and is responsible for ensuring that the game logic is executed in the correct sequence.
 */
export class GameManager {
    // Root visual component
    private _root: PIXI.Container = new PIXI.Container();
    // Core components
    private _renderer: Renderer;
    private _layoutManager: LayoutManager = null!;
    private _dataManager: DataManager;
    private _winManager: WinManager;
    // Controllers
    private _spinController: SpinController = null!;
    private _stageController: StageController = null!;
    private _pressureController: PressureController = null!;
    private _skillWindowController: SkillWindowController = null!;
    private _nudgeController: NudgeController = null!;
    // State management
    private _gameStateMachine: GameStateMachine;
    // Scenes
    private _baseGameScene: BaseGameScene = null!;
    private _uiScene: UIScene = null!;
    private _lobbyScene: LobbyScene = null!;
    private _stageEndScene: StageEndScene = null!;
    private _relicSelectScene: RelicSelectScene = null!;
    // Relic system
    private _relicManager: RelicManager = new RelicManager();
    // Run history — persisted in memory for the session, will move to ProgressionManager in Milestone 3
    private _runsCompleted: number = 0;
    private _lastScore: number = 0;
    private _bestScore: number = 0;

    // Constructor
    public constructor(renderer: Renderer) {
        // Core component initialization
        this._renderer = renderer;
        this._winManager = new WinManager({
            winLines: winConfig.winConfig.winlines,
            paytable: winConfig.winConfig.paytable
        });
        this._gameStateMachine = new GameStateMachine();
        // Data loading and initialization
        this._dataManager = new DataManager();
        // Must wait for data to create scenes and spin controller
        Promise.all([
            once(this._dataManager.testDataLoaded, 'testDataLoaded'),
            once(this._dataManager.reelsetDataLoaded, 'reelsetsLoaded')
        ]).then(() => {
            // Initialize spin controller
            this._spinController = new SpinController(
                this._gameStateMachine,
                this._dataManager.reelsets,
                this._dataManager.spinData
            );
            this._stageController = new StageController(this._spinController);
            this._pressureController = new PressureController(this._spinController);
            this._skillWindowController = new SkillWindowController(this._spinController);
            this._nudgeController = new NudgeController(this._spinController);
            // Scene and layout initialization
            this._baseGameScene = new BaseGameScene(this._renderer);
            this._uiScene = new UIScene(this._renderer, this._gameStateMachine, this._dataManager.spinData);
            this._lobbyScene = new LobbyScene();
            this._stageEndScene = new StageEndScene();
            this._relicSelectScene = new RelicSelectScene();
            this._layoutManager = new LayoutManager(
                this._renderer.app,
                this._root,
                this._baseGameScene,
                this._uiScene
            );
            // Start game loop when all scenes, core components, and data are created
            this._init();
        });
    }

    /**
     * Initializes game scenes, sets up event listeners for game flow coordination, and starts the game loop.
     */
    private async _init() {
        // Initialize scenes
        await this._baseGameScene.init();
        await this._uiScene.init();
        await this._lobbyScene.init();
        await this._stageEndScene.init();
        await this._relicSelectScene.init();

        // Set up visual root
        this._renderer.stage.addChild(this._root);
        // Game and UI scenes live inside root so LayoutManager can scale them together
        this._root.addChild(this._baseGameScene, this._uiScene);
        // Overlay scenes live directly on stage so they always position in screen space,
        // unaffected by the LayoutManager's root scale and offset
        this._renderer.stage.addChild(this._lobbyScene, this._stageEndScene, this._relicSelectScene);

        // Give relic-aware controllers access to the relic manager
        this._pressureController.relicManager = this._relicManager;
        this._nudgeController.relicManager = this._relicManager;

        // Pulse the tray icon whenever a relic effect fires
        this._relicManager.onRelicActivated.on('activated', (id: string) => {
            this._uiScene.pulseRelic(id);
        });

        // Connect spin controller to slot container and set initial reelset
        this._spinController.slotContainer = this._baseGameScene.slotContainer;
        this._baseGameScene.slotContainer.setReelset(this._dataManager.reelsets[0]);

        // Set up spin controller update loop, skill window polling, and nudge timer
        this._renderer.ticker.add((ticker) => {
            const delta = ticker.deltaMS / 1000;
            this._spinController.update(delta);
            this._skillWindowController.update();
            this._nudgeController.update(delta);
        });

        // All reels stopped — open the nudge window before evaluating the result
        this._spinController.onAllReelsStopped.on('stopped', () => {
            this._nudgeController.startWindow();
        });

        // Nudge window closed — collect final reel positions and resolve the spin
        this._nudgeController.onWindowClosed.on('closed', () => {
            this._spinController.resolveNudge();
        });

        // Nudge button pressed — apply the nudge to that reel
        this._baseGameScene.slotContainer.onNudgePressed.on('nudge', (reelIndex: number, direction: 'up' | 'down') => {
            this._nudgeController.applyNudge(reelIndex, direction);
        });

        // Set up spin complete evaluation and win display
        this._spinController.onSpinComplete.on('complete', (spinResult: number[]) => {
            this._skillWindowController.clearAll();
            const result = this._winManager.evaluateWin(spinResult, this._spinController.activeReelset!);
            const modifiedWin = this._relicManager.processWin(result.totalWin);
            const displayResult = { ...result, totalWin: modifiedWin };
            this._stageController.addWin(modifiedWin);
            this._baseGameScene.slotContainer.showWin(displayResult);
            // addWin drives pressure reduction and checks for stage end — always call, even on 0 win
            this._pressureController.addWin(modifiedWin);
        });

        // Forward stage spin count updates to the UI
        this._stageController.onCountChanged.on('changed', (count: number) => {
            this._uiScene.updateSpinCount(count);
        });

        // Forward stage win total updates to the UI
        this._stageController.onWinChanged.on('changed', (total: number) => {
            this._uiScene.updateTotalWin(total);
        });

        // Forward pressure updates to the UI bar and the in-world corruption overlay
        this._pressureController.onPressureChanged.on('changed', (_pressure: number, _max: number, ratio: number) => {
            this._uiScene.updatePressure(ratio);
            this._baseGameScene.setCorruptionLevel(ratio);
        });

        // Threshold crossings — swap the active reelset to progressively more corrupted strips
        this._pressureController.onThresholdReached.on('reached', (threshold: number) => {
            if (threshold === 50) {
                this._swapReelset('temple1_corrupted');
            } else if (threshold === 75) {
                this._swapReelset('temple1_deep_corruption');
            }
        });

        // Stage ended — corruption filled, record results and show stage end screen
        this._pressureController.onStageEnded.on('ended', () => {
            this._gameStateMachine.tryGoToState(GameState.STAGE_END);
            this._runsCompleted++;
            this._lastScore = this._stageController.totalWin;
            if (this._lastScore > this._bestScore) this._bestScore = this._lastScore;
            this._showStageEnd();
        });

        // Lobby start button — begin a new stage
        this._lobbyScene.onStartStage.on(LOBBY_START_EVENT, () => {
            this._startStage();
        });

        // Stage end continue button — go to relic selection before returning to lobby
        this._stageEndScene.onContinue.on(STAGE_END_CONTINUE_EVENT, () => {
            this._pressureController.resetStage();
            this._showRelicSelect();
        });

        // Relic selected — carry it into the run, update the UI tray, then return to lobby
        this._relicSelectScene.onRelicSelected.on(RELIC_SELECTED_EVENT, (relic: RelicData) => {
            this._relicManager.addRelic(relic);
            this._uiScene.addRelicToTray(relic);
            this._relicSelectScene.hide();
            this._gameStateMachine.tryGoToState(GameState.LOBBY);
            this._showLobby();
        });

        // Set up UI button listeners
        this._setupButtonListeners();
        // Set up listeners to trigger layout updates
        this._setupLayout();

        // Begin in lobby
        this._showLobby();
    }

    private _startStage(): void {
        this._lobbyScene.hide();
        this._stageEndScene.hide();
        this._baseGameScene.visible = true;
        this._uiScene.visible = true;
        this._gameStateMachine.tryGoToState(GameState.IDLE);
        this._stageController.startStage();
        this._pressureController.startStage();
        this._relicManager.onStageStart();
        // Reset to the base reelset and clear corruption visuals at the start of each stage
        this._swapReelset('temple1');
        this._baseGameScene.setCorruptionLevel(0);
    }

    /**
     * Swaps the active reelset in both the spin controller and the slot container.
     * The slot container rebuild is safe here because swaps only trigger between spins (IDLE state).
     */
    private _swapReelset(id: string): void {
        const reelset = this._dataManager.reelsets.find(r => r.id === id);
        if (!reelset) return;
        this._spinController.setActiveReelset(id);
        this._baseGameScene.slotContainer.setReelset(reelset);
    }

    private _showLobby(): void {
        this._baseGameScene.visible = false;
        this._uiScene.visible = false;
        this._stageEndScene.hide();
        this._relicSelectScene.hide();
        this._centerOnScreen(this._lobbyScene);
        this._lobbyScene.show(this._runsCompleted, this._lastScore, this._bestScore);
    }

    private _showRelicSelect(): void {
        const options = this._relicManager.getRandomOptions(3);
        if (options.length === 0) {
            // All relics already owned — skip straight to lobby
            this._gameStateMachine.tryGoToState(GameState.LOBBY);
            this._showLobby();
            return;
        }
        this._centerOnScreen(this._relicSelectScene);
        this._relicSelectScene.show(options);
    }

    private _showStageEnd(): void {
        this._baseGameScene.slotContainer.clearWin();
        this._baseGameScene.visible = false;
        this._uiScene.visible = false;
        this._centerOnScreen(this._stageEndScene);
        this._stageEndScene.show(
            this._stageController.spinCount,
            this._stageController.totalWin
        );
    }

    /**
     * Centers a scene on the screen in screen space. Called for overlay scenes that
     * live on stage directly rather than inside the scaled root container.
     */
    private _centerOnScreen(scene: { setPosition: (x: number, y: number) => void }): void {
        const screen = this._renderer.app.screen;
        scene.setPosition(screen.width / 2, screen.height / 2);
    }

    private _setupButtonListeners(): void {
        // Set up UI spin button to trigger spins in the spin controller
        this._uiScene.spin.on(SPIN_EVENT, (spinKey) => {
            this._baseGameScene.slotContainer.clearWin();
            this._spinController.spin(spinKey);
        });
        // Set up UI stop button to trigger stopping the next column in the spin controller
        this._uiScene.stop.on(STOP_COLUMN_EVENT, () => {
            this._spinController.stopNextColumn();
        });
    }

    private _setupLayout(): void {
        const handleLayout = () => {
            requestAnimationFrame(() => {
                this._layoutManager.layout();
                this._baseGameScene.updateLayout();
                // Re-center any visible overlay scenes after layout changes
                if (this._lobbyScene.visible) this._centerOnScreen(this._lobbyScene);
                if (this._stageEndScene.visible) this._centerOnScreen(this._stageEndScene);
            });
        };
        window.addEventListener('resize', handleLayout);
        window.addEventListener('orientationchange', handleLayout);
        window.visualViewport?.addEventListener('orientationchange', handleLayout);
        window.visualViewport?.addEventListener('resize', handleLayout);
        this._renderer.app.ticker.addOnce(() => handleLayout());
        requestAnimationFrame(() => {
            this._layoutManager.layout();
            this._baseGameScene.updateLayout();
        });
    }
}

export default GameManager;
