import { EventEmitter } from 'events';
import { SpinController } from '../spin/SpinController';
import nudgeConfig from '../config/nudge.config.json';
import { RelicManager } from '../relic/RelicManager';

/**
 * NudgeController manages the post-stop nudge window.
 * When all reels are idle (NUDGE state), it shows the arrow buttons, runs a countdown,
 * fades the buttons out over the window duration, and resolves the spin when time expires.
 * Players can nudge any reel once during this window — clicking a button immediately
 * hides that reel's arrows and shifts the reel one row in the chosen direction.
 * The window also closes early if all reels have been nudged.
 */
export class NudgeController {
    private _spinController: SpinController;
    private _windowDuration: number;
    private _totalWindowTime: number = 0;
    private _timeRemaining: number = 0;
    private _windowOpen: boolean = false;
    private _reelsNudged: boolean[] = [];
    private _relicManager: RelicManager | null = null;
    // GameManager subscribes to trigger resolveNudge() on SpinController
    private _onWindowClosed: EventEmitter = new EventEmitter();

    // Getters
    public get onWindowClosed(): EventEmitter { return this._onWindowClosed; }
    public set relicManager(rm: RelicManager) { this._relicManager = rm; }

    // Constructor
    constructor(spinController: SpinController) {
        this._spinController = spinController;
        this._windowDuration = nudgeConfig.nudgeConfig.windowDuration;
    }

    /**
     * Opens the nudge window. Called by GameManager when SpinController emits onAllReelsStopped.
     */
    public startWindow(): void {
        const container = this._spinController.slotContainer;
        if (!container) return;
        const reelCount = container.reels.length;
        const bonus = this._relicManager?.getNudgeWindowBonus() ?? 0;
        this._totalWindowTime = this._windowDuration + bonus;
        this._timeRemaining = this._totalWindowTime;
        this._reelsNudged = new Array(reelCount).fill(false);
        this._windowOpen = true;
        container.showNudgeButtons();
    }

    /**
     * Applies a nudge to the given reel. Called by GameManager when a nudge button is pressed.
     * One nudge per reel — subsequent presses on the same reel are ignored.
     */
    public applyNudge(reelIndex: number, direction: 'up' | 'down'): void {
        if (!this._windowOpen || this._reelsNudged[reelIndex]) return;
        const container = this._spinController.slotContainer;
        container.reels[reelIndex].nudge(direction);
        this._reelsNudged[reelIndex] = true;
        container.hideNudgeButtonsForReel(reelIndex);
        // Close early if every reel has been nudged
        if (this._reelsNudged.every(nudged => nudged)) {
            this._closeWindow();
        }
    }

    /**
     * Ticked every frame while the window is open. Fades buttons and closes when time runs out.
     */
    public update(delta: number): void {
        if (!this._windowOpen) return;
        this._timeRemaining -= delta;
        const ratio = Math.max(0, this._timeRemaining / this._totalWindowTime);
        this._spinController.slotContainer.updateNudgeAlpha(ratio);
        if (this._timeRemaining <= 0) {
            this._closeWindow();
        }
    }

    /**
     * Force-closes the window without waiting for the timer. Safe to call when the stage ends mid-spin.
     */
    public forceClose(): void {
        if (this._windowOpen) this._closeWindow();
    }

    private _closeWindow(): void {
        this._windowOpen = false;
        this._spinController.slotContainer.hideAllNudgeButtons();
        this._onWindowClosed.emit('closed');
    }
}
