import { SlotContainer } from './SlotContainer';
import baseSlotConfig from '../config/baseSlot.config.json';
import baseReelConfig from '../config/baseReel.config.json';
import { Reel } from './Reel';
import { SymbolModel } from './model/SymbolModel';
import { ReelStrip } from './ReelStrip';
import * as PIXI from 'pixi.js';
import { NUM_REELS, NUM_ROWS } from '../Constants';
import { ReelsetData } from '../data/DataManager';
import { WinBox } from '../ui/WinBox';
import { WinResult } from '../win/WinManager';
import winConfig from '../config/wins.config.json';
import { EventEmitter } from 'events';

/**
 * BaseSlotContainer is an implementation of SlotContainer for the Base Game.
 * It manages the reels, symbols, and win box for the slot machine game. 
 * It initializes the reels based on the provided symbol models and reel set data, and handles the layout and updates of the reels and win box during gameplay.
 */
export class BaseSlotContainer extends SlotContainer {
    // Visual
    private _symbolModels: SymbolModel[] = [];
    private _reelMask: PIXI.Graphics = new PIXI.Graphics();
    private _reelContainer: PIXI.Container = new PIXI.Container();
    // Data
    private _reelset: ReelsetData | null = null;
    // Win display
    private _winBox!: WinBox;
    private _winLines: PIXI.Graphics = new PIXI.Graphics();
    // Nudge buttons — one up/down pair per reel, hidden until the nudge window opens
    private _nudgeOverlay: PIXI.Container = new PIXI.Container();
    private _nudgeButtonGroups: Array<{ up: PIXI.Container; down: PIXI.Container }> = [];
    private _onNudgePressed: EventEmitter = new EventEmitter();

    // Getters
    public get symbolModels(): SymbolModel[] {
        return this._symbolModels;
    }

    public get onNudgePressed(): EventEmitter {
        return this._onNudgePressed;
    }

    // Constructor
    public constructor(symbolModels: SymbolModel[]) {
        super();
        this._symbolModels = symbolModels;
        this._init();
    }

    /**
     * Update the reel set data and rebuild the reels accordingly
     */
    public setReelset(reelset: ReelsetData): void {
        this._reelset = reelset;
        this._rebuildReels();
        this.layout();
    }

    /**
     * Update method to be called on each game tick, which updates the state of each reel based on the elapsed time (delta).
     */
    public update(delta: number): void {
        this._reels.forEach((reel) => reel.update(delta));
    }

    /**
     * Update the reels' state during a spin based on the elapsed spin time. 
     * This method checks if each reel should stop spinning based on the configured spin duration and delay for each reel.
     */
    public updateSpin(spinTimer: number): void {
        this._reels.forEach((reel, index) => {
            const delay = index * baseSlotConfig.baseSlotConfig.reelSpinDelay;
            if (spinTimer >= delay + baseSlotConfig.baseSlotConfig.spinDuration) {
                // reel.stop();
            }
        });
    }

    /**
     * Display the win amount in the win box.
     */

    public showWin(win: WinResult): void {
        this._winBox.show(win.totalWin);
        this._drawWinLines(win);
        this.layout();
    }

    /**
     * Setup layout based on Reels size and position. 
     * Update the reel mask and win box position accordingly.
     */
    public layout(): void {
        // Layout reels
        const reelWidth = baseReelConfig.baseReelConfig.reelWidth;
        const symbolHeight = baseReelConfig.baseReelConfig.symbolHeight;
        const totalWidth = reelWidth * NUM_REELS;
        const totalHeight = symbolHeight * NUM_ROWS;
        // Update reel mask
        this._reelMask
            .clear()
            .rect(0, 0, totalWidth, totalHeight)
            .fill(0xffffff);
        // Update win box 
        this._winBox.resize(totalWidth);
        this._winBox.position.set(totalWidth * 0.5, totalHeight);
    }

    /**
     * Clear the win lines from the previous win display.
     */
    public clearWin(): void {
        this._winLines.clear();
        this._winBox.clear();
    }

    /**
     * Shows the nudge buttons for all reels at the start of the nudge window.
     */
    public showNudgeButtons(): void {
        this._nudgeButtonGroups.forEach(group => {
            group.up.visible = true;
            group.down.visible = true;
            group.up.alpha = 1;
            group.down.alpha = 1;
        });
    }

    /**
     * Hides the nudge buttons for a single reel after it has been nudged.
     */
    public hideNudgeButtonsForReel(index: number): void {
        const group = this._nudgeButtonGroups[index];
        if (!group) return;
        group.up.visible = false;
        group.down.visible = false;
    }

    /**
     * Hides all nudge buttons. Called when the nudge window closes.
     */
    public hideAllNudgeButtons(): void {
        this._nudgeButtonGroups.forEach(group => {
            group.up.visible = false;
            group.down.visible = false;
        });
    }

    /**
     * Fades all still-visible nudge buttons to the given ratio (1 → 0) over the window duration.
     */
    public updateNudgeAlpha(ratio: number): void {
        this._nudgeButtonGroups.forEach(group => {
            if (group.up.visible) group.up.alpha = ratio;
            if (group.down.visible) group.down.alpha = ratio;
        });
    }

    /**
     * Initialze the slot container by setting up the reels, reel mask, and win box.
     */
    private _init(): void {
        this._container.addChild(this._reelContainer);
        this._setupMask();
        this._setupWinbox();
        this._container.addChild(this._winLines);
        // Nudge overlay sits above win lines so buttons are always on top
        this._container.addChild(this._nudgeOverlay);
    }

    /**
     * Reset and rebuild the reels based on the current reel set data.
     */
    private _rebuildReels(): void {
        this._reels.forEach(reel => {
            this._reelContainer.removeChild(reel.container);
        });
        this._reels = [];
        // Clear old nudge buttons before rebuilding so they stay in sync with new reels
        this._nudgeOverlay.removeChildren();
        this._nudgeButtonGroups = [];
        this._setupReels();
    }

    /**
     * Setup the reels based on the current reel set data and symbol models.
     */
    private _setupReels(): void {
        // Ensure reel set data is available before setting up reels
        if (!this._reelset) return;

        // Create reels based on reel set data and symbol models
        const reelWidth = baseReelConfig.baseReelConfig.reelWidth;
        const reelHeight = baseReelConfig.baseReelConfig.reelHeight;
        for (let i = 0; i < baseSlotConfig.baseSlotConfig.numReels; i++) {
            const stripData = this._reelset.reels[i];
            const symbols = stripData.map(id => this._symbolModels[id]);
            const reelStrip = new ReelStrip(symbols);
            const reel = new Reel(
                reelStrip,
                reelWidth,
                reelHeight
            );
            reel.container.x = i * reelWidth;
            this._reelContainer.addChild(reel.container);
            this._reels.push(reel);
            this._buildNudgeButtonsForReel(i, reelWidth);
        }
    }

    /**
     * Builds a pair of arrow buttons (up/down) for the given reel index and adds them
     * to the nudge overlay. Buttons are invisible until showNudgeButtons() is called.
     */
    private _buildNudgeButtonsForReel(reelIndex: number, reelWidth: number): void {
        const symbolHeight = baseReelConfig.baseReelConfig.symbolHeight;
        const totalHeight = symbolHeight * NUM_ROWS;
        const cx = reelIndex * reelWidth + reelWidth / 2;

        const makeArrow = (direction: 'up' | 'down'): PIXI.Container => {
            const view = new PIXI.Container();
            // Semi-transparent backing for click area
            const bg = new PIXI.Graphics().rect(-22, -13, 44, 26).fill({ color: 0x000000, alpha: 0.55 });
            // Gold triangle pointing in the nudge direction
            const arrow = new PIXI.Graphics();
            if (direction === 'up') {
                arrow.poly([-13, 9, 0, -9, 13, 9]).fill(0xd4af37);
            } else {
                arrow.poly([-13, -9, 0, 9, 13, -9]).fill(0xd4af37);
            }
            view.addChild(bg, arrow);
            view.eventMode = 'static';
            view.cursor = 'pointer';
            view.visible = false;
            view.on('pointerdown', () => {
                this._onNudgePressed.emit('nudge', reelIndex, direction);
            });
            return view;
        };

        const up = makeArrow('up');
        const down = makeArrow('down');
        up.position.set(cx, 22);
        down.position.set(cx, totalHeight - 22);
        this._nudgeOverlay.addChild(up, down);
        this._nudgeButtonGroups[reelIndex] = { up, down };
    }

    /**
     * Setup the reel mask to ensure that only the visible portion of the reels is displayed.
     */
    private _setupMask(): void {
        this._reelContainer.addChild(this._reelMask);
        this._reelContainer.mask = this._reelMask;
    }

    /**
     * Setup the win box which will display the win amount when the player wins. 
     * The win box is positioned below the reels and is resized based on the total width of the reels.
     */
    private _setupWinbox(): void {
        this._winBox = new WinBox(this.width);
        this._container.addChild(this._winBox);
    }

    /**
     * Draw the win lines on the reels based on the win result. 
     * Each win line is drawn with a different color for visual distinction, and the positions of the win lines are determined by the configuration in the winConfig file.
     */
    private _drawWinLines(wins: WinResult): void {
        const reelWidth = baseReelConfig.baseReelConfig.reelWidth;
        const symbolHeight = baseReelConfig.baseReelConfig.symbolHeight;
        // Iterate through each win in the win result and draw the corresponding win line on the reels.
        wins.wins.forEach((win, index) => {
            const line = winConfig.winConfig.winlines.find(line => line.id === win.lineId)?.positions;
            if (!line) return;
            // Set a unique color for each win line based on its index for visual distinction.
            const color = Math.random() * 0xffffff;
            this._winLines.setStrokeStyle({ width: 4, color });
            this._winLines.moveTo(
                reelWidth * 0.5,
                line[0] * symbolHeight + symbolHeight * 0.5
            );
            // Iterate through each position in the win line and draw a line connecting the positions across the reels.
            for (let i = 1; i < line.length; i++) {
                this._winLines.lineTo(
                    reelWidth * i + reelWidth * 0.5,
                    line[i] * symbolHeight + symbolHeight * 0.5
                );
            }
            this._winLines.stroke();
        });
    }
}

export default BaseSlotContainer;