import Renderer from '../renderer/Renderer';
import BaseSlotContainer from '../slot/BaseSlotContainer';
import { SymbolModel } from '../slot/model/SymbolModel';
import { Scene } from './Scene';
import symbolsConfig from '../config/symbols.config.json';
import * as PIXI from 'pixi.js';
import { CorruptionOverlay } from '../fx/CorruptionOverlay';
import { NUM_REELS, NUM_ROWS } from '../Constants';
import baseReelConfig from '../config/baseReel.config.json';

/**
 * BaseGameScene is responsible for rendering the main game scene, which includes the slot container and the background. 
 * It initializes the slot container with the symbol models and manages the layout of the game scene elements. 
 * The scene also provides access to the slot container and its bounds for layout purposes.
 */
export class BaseGameScene extends Scene {
    // Renderer reference 
    private _renderer: Renderer;
    // Visual components
    private _slotContainer: BaseSlotContainer = null!;
    private _corruptionOverlay: CorruptionOverlay = null!;
    private _baseGameBg: PIXI.Sprite = null!;
    private _bgContainer: PIXI.Container = new PIXI.Container();
    private _layoutContainer: PIXI.Container = new PIXI.Container();

    // Getters
    public get slotContainer(): BaseSlotContainer {
        return this._slotContainer;
    }

    public get slotBounds(): PIXI.Bounds {
        return this._slotContainer.container.getLocalBounds();
    }

    public get backgroundLayer(): PIXI.Container {
        return this._bgContainer;
    }

    // Contructor
    public constructor(renderer: Renderer) {
        super();
        this._renderer = renderer;
    }

    /**
     * Initialization method to set up the scene, load assets, and create visual components.
     */
    public async init(): Promise<void> {
        // Anchor Scene to center
        this.anchor.set(0.5);
        // Set up container hierarchy
        this.addChild(this._layoutContainer);
        this._layoutContainer.addChild(this._container);
        // Load symbol textures and initialize slot container
        await this._renderer.loadAssets(symbolsConfig);
        this._initializeBaseSlotContainer();
        this._updateAnchor();
        // Load background asset and set up background sprite
        await this._renderer.loadAssets({ background: './resources/assets/backgrounds/baseGameBg.jpg' });
        this._baseGameBg = new PIXI.Sprite(PIXI.Assets.get('./resources/assets/backgrounds/baseGameBg.jpg'));
        this._baseGameBg.anchor.set(0.5);
        // Add background to its container and add to stage
        this._bgContainer.addChild(this._baseGameBg);
        this._renderer.stage.addChild(this._bgContainer);

    }

    /**
     * Public layout method to be called by the LayoutManager when the screen size changes. 
     * It recalculates the scale and position of the background to ensure it covers the entire screen while maintaining its aspect ratio. 
     */
    public updateLayout(): void {
        // Check for background sprite
        if (!this._baseGameBg) return;
        // Get screen dimensions and calculate scale to cover the screen while maintaining aspect ratio
        const screen = this._renderer.app.screen;
        const scale = Math.max(
            screen.width / this._baseGameBg.texture.width,
            screen.height / this._baseGameBg.texture.height
        );
        // Apply scale and position background at the center of the screen
        this._baseGameBg.scale.set(scale);
        this._baseGameBg.position.set(screen.width * 0.5, screen.height * 0.5);
    }

    /**
     * Updates the corruption overlay intensity. Called by GameManager when pressure changes.
     */
    public setCorruptionLevel(ratio: number): void {
        this._corruptionOverlay.setIntensity(ratio);
    }

    /**
     * Initializes the BaseSlotContainer with SymbolModels created from the symbols configuration,
     * then layers the corruption overlay on top.
     */
    private _initializeBaseSlotContainer(): void {
        // Create SymbolModels from configuration
        const symbolModels = symbolsConfig.symbols.map(symbol => new SymbolModel(symbol.name, symbol.texture));
        // Initialize BaseSlotContainer with the created SymbolModels and add it to the scene
        this._slotContainer = new BaseSlotContainer(symbolModels);
        this._container.addChild(this._slotContainer.container);
        // Corruption overlay sits above the reels — covers exactly the visible slot area
        const slotWidth = baseReelConfig.baseReelConfig.reelWidth * NUM_REELS;
        const slotHeight = baseReelConfig.baseReelConfig.symbolHeight * NUM_ROWS;
        this._corruptionOverlay = new CorruptionOverlay(slotWidth, slotHeight);
        this._container.addChild(this._corruptionOverlay);
    }
}

export default BaseGameScene;