import { SYMBOLS } from '../Constants';
import { ReelsetData } from '../data/DataManager';

/**
 * WinLine represents a specific payline in the slot machine, defined by its unique ID and the positions of symbols on each reel that form the line.
 */
interface WinLine {
    id: string;
    positions: number[]
}

/**
 * WinConfig defines the configuration from the winConfig for the WinManager, including the paylines (winLines) and the paytable that maps symbol IDs to their respective payout values.
 */
export interface WinConfig {
    winLines: WinLine[];
    paytable: Record<number, number>;
}

/**
 * WinResult represents the outcome of evaluating a spin result against the defined paylines and paytable. 
 * It includes the total win amount and an array of individual wins, each detailing the line ID, symbol ID, count of symbols, and payout for that line.
 */
export interface WinResult {
    totalWin: number;
    wins: {
        lineId: string;
        symbolId: number;
        count: number;
        payout: number;
    }[];
}

/**
 * WinManager is responsible for evaluating the results of a spin against the defined paylines and paytable to calculate the total win amount and details of each winning line.
 */
export class WinManager {
    private _winLines: WinLine[] = [];
    private _paytable: Record<number, number>;

    // Constructor
    constructor(config: WinConfig) {
        this._winLines = config.winLines;
        this._paytable = config.paytable;
    }

    /**
     * Evaluate the spin result against the defined paylines and paytable to calculate the total win amount and details of each winning line.
     */
    public evaluateWin(spinResult: number[] | null, reelSet: ReelsetData): WinResult {
        let totalWin = 0;
        const wins: WinResult['wins'] = [];
        // If spinResult is null, it means the spin was not successful or not completed, so we return a total win of 0 and an empty wins array.
        if (!spinResult) {
            return { totalWin, wins };
        }
        // Loop through each defined win line and evaluate the symbols on that line based on the spin result and reel set data.
        for (const winLine of this._winLines) {
            const symbols: number[] = [];
            // For each reel in the win line, determine the symbol that is in the position defined by the win line's positions array, taking into account the spin result and the reel strip from the reel set data.
            for (let reelIndex = 0; reelIndex < winLine.positions.length; reelIndex++) {
                const reelStrip = reelSet.reels[reelIndex];
                const stopIndex = spinResult[reelIndex];
                const rowOffset = winLine.positions[reelIndex];
                const symbolIndex = (stopIndex + rowOffset + 1 + reelStrip.length) % reelStrip.length;
                const symbolId = reelStrip[symbolIndex];
                // Collect the symbol ID for the current position on the win line.
                symbols.push(symbolId);
            }
            // Log evaluated symbols per winline for debugging visual vs evaluation mismatches
            console.log(`[WinManager] ${winLine.id}: stopIndices=[${winLine.positions.map((_, i) => spinResult[i])}] → symbols=[${symbols}]`);
            // Evaluate the collected symbols for the current win line against the paytable to determine if there is a win and calculate the payout.
            const winEvaluation = this._evaluateWinLine(symbols);
            if (winEvaluation.payout > 0) {
                totalWin += winEvaluation.payout;
                wins.push({
                    lineId: winLine.id,
                    symbolId: winEvaluation.symbolId,
                    count: winEvaluation.count,
                    payout: winEvaluation.payout
                });
            }
        }
        return {
            totalWin,
            wins
        };
    }

    /**
     * Evaluate the symbols on a win line against the paytable to determine if there is a win and calculate the payout.
     */
    private _evaluateWinLine(symbols: number[]): { symbolId: number; count: number; payout: number } {
        let symbolId = symbols[0];
        // If the first symbol is a WILD, we need to determine the base symbol for the win line by looking for the first non-WILD symbol in the line. If all symbols are WILD, we can treat it as a win of WILD symbols.
        if (symbolId === SYMBOLS.WILD) {
            const firstNonWild = symbols.find(symbol => symbol !== SYMBOLS.WILD);
            symbolId = firstNonWild ?? SYMBOLS.WILD;
        }
        let baseSymbol: number | null = null;
        let count = 0;
        // Loop through the symbols on the win line to count how many consecutive symbols match the base symbol (or are WILD) starting from the leftmost position. 
        // The win line is considered broken when we encounter a symbol that is different from the base symbol and is not a WILD.
        for (let i = 0; i < symbols.length; i++) {
            const symbol = symbols[i];
            // If the symbol is a WILD, it can substitute for any symbol, so we count it as part of the win line and continue to the next symbol.
            if (symbol === SYMBOLS.WILD) {
                count++;
                continue;
            }
            // If we haven't set a base symbol yet, we set it to the current symbol and continue counting.
            if (baseSymbol === null) {
                baseSymbol = symbol;
                count++;
                continue;
            }
            // If the current symbol is different from the base symbol, it means the win line has been broken, so we stop counting.
            if (symbol !== baseSymbol) {
                break;
            }
            count++;
        }
        // If the count of matching symbols (including WILDs) is less than 3, it does not qualify as a win, so we return a payout of 0.
        if (count < 3) {
            return { symbolId, count, payout: 0 };
        }
        // Look up the payout for the symbol ID and count of symbols in the paytable. 
        // If there is no entry in the paytable for the symbol ID, we treat it as a payout of 0.
        const payout = this._paytable[symbolId] ?? 0;
        return {
            symbolId: symbolId,
            count,
            payout: payout * count
        }
    }
}