import * as PIXI from 'pixi.js';
import { EventEmitter } from 'events';
import { Scene } from './Scene';
import { Button } from '../ui/Button';

export const LOBBY_START_EVENT = 'startStage';

/**
 * LobbyScene is the persistent home screen between stages.
 * It displays the player's run history and provides the entry point to start a new stage.
 * Stats are updated via show() each time the lobby becomes visible.
 * GameManager listens to onStartStage to transition to IDLE and kick off StageController.
 */
export class LobbyScene extends Scene {
    // Event emitter for the start button — GameManager subscribes to trigger stage flow
    private _onStartStage: EventEmitter = new EventEmitter();
    // Stat display text elements — populated by show() on each visit
    private _bestScoreText: PIXI.Text = null!;
    private _lastScoreText: PIXI.Text = null!;
    private _runsText: PIXI.Text = null!;

    // Getters
    public get onStartStage(): EventEmitter {
        return this._onStartStage;
    }

    // Constructor
    public async init(): Promise<void> {
        this._buildUI();
        this._updateAnchor();
    }

    /**
     * Updates the lobby display with the latest run stats and makes the scene visible.
     * Called by GameManager each time the player returns to the lobby.
     */
    public show(runsCompleted: number, lastScore: number, bestScore: number): void {
        this._runsText.text = `Descents completed: ${runsCompleted}`;
        this._lastScoreText.text = `Last score: ${lastScore.toFixed(2)}`;
        this._bestScoreText.text = `Best score: ${bestScore.toFixed(2)}`;
        this.visible = true;
    }

    /**
     * Hides the scene. Called by GameManager when transitioning into a stage.
     */
    public hide(): void {
        this.visible = false;
    }

    /**
     * Builds the lobby UI — background, title, stat displays, and start button.
     */
    private _buildUI(): void {
        const bg = new PIXI.Graphics().rect(-300, -250, 600, 500).fill({ color: 0x000000, alpha: 0.9 });
        this._container.addChild(bg);

        const title = new PIXI.Text({
            text: 'The Sunken Rites',
            style: new PIXI.TextStyle({ fill: 0xffffff, fontSize: 36, fontWeight: 'bold', align: 'center' })
        });
        title.anchor.set(0.5);
        title.position.set(0, -180);
        this._container.addChild(title);

        // Stat text elements — content set by show() each visit
        this._runsText = this._makeStatText(0, -100);
        this._lastScoreText = this._makeStatText(0, -55);
        this._bestScoreText = this._makeStatText(0, -10);

        // Start button — emits LOBBY_START_EVENT for GameManager to begin a new stage
        const button = new Button(() => {
            this._onStartStage.emit(LOBBY_START_EVENT);
        }, (g) => {
            g.rect(-110, -28, 220, 56).fill(0x333333);
            g.rect(-110, -28, 220, 56).stroke({ color: 0x888888, width: 1 });
            const label = new PIXI.Text({
                text: 'Begin Descent',
                style: new PIXI.TextStyle({ fill: 0xffffff, fontSize: 20 })
            });
            label.anchor.set(0.5);
            g.addChild(label);
        });
        button.view.position.set(0, 100);
        this._container.addChild(button.view);
    }

    /**
     * Creates a styled stat text element and adds it to the container at the given position.
     */
    private _makeStatText(x: number, y: number): PIXI.Text {
        const t = new PIXI.Text({
            text: '',
            style: new PIXI.TextStyle({ fill: 0xcccccc, fontSize: 18, align: 'center' })
        });
        t.anchor.set(0.5);
        t.position.set(x, y);
        this._container.addChild(t);
        return t;
    }
}
