import { SpinController } from '../spin/SpinController';
import { ReelState } from '../slot/Reel';
import skillWindowConfig from '../config/skillWindow.config.json';

/**
 * SkillWindowController provides a subtle visual assist to help players read approaching symbols.
 * Each tick it checks the buffer symbol above the visible window for every spinning reel.
 * When a symbol at or above the configured threshold is about to enter the visible area,
 * the reel's highlight border activates — giving the player a cue without replacing the
 * skill of reading the reel directly.
 *
 * The threshold is config-driven so different temples or Rite Memory upgrades can widen
 * or shift what qualifies. No events are needed — this is a pure polling system.
 */
export class SkillWindowController {
    private _spinController: SpinController;
    private _threshold: number;

    constructor(spinController: SpinController) {
        this._spinController = spinController;
        this._threshold = skillWindowConfig.skillWindowConfig.highlightThreshold;
    }

    /**
     * Called every tick. Reads the approaching symbol for each spinning reel and
     * toggles its highlight accordingly. Clears all highlights when not spinning.
     */
    public update(): void {
        const reelset = this._spinController.activeReelset;
        const reels = this._spinController.slotContainer?.reels;
        if (!reels || !reelset) return;

        reels.forEach((reel, i) => {
            if (reel.reelState !== ReelState.SPINNING) {
                reel.showHighlight(false);
                return;
            }
            // currentIndex is the buffer symbol sitting just above the visible window —
            // the next symbol to roll into the TOP row on the next recycle.
            const approachingSymbolId = reelset.reels[i][reel.currentIndex];
            reel.showHighlight(approachingSymbolId >= this._threshold);
        });
    }

    /**
     * Clears all highlights immediately. Call on spin complete or stage reset.
     */
    public clearAll(): void {
        const reels = this._spinController.slotContainer?.reels;
        if (!reels) return;
        reels.forEach(reel => reel.showHighlight(false));
    }
}
